insert into public.knowledge_entries
  (type, title, body, category, tags, source_type, source_id, source_title, status, confidence, created_by)
values
('term','APS(Attending Physician Statement, 주치의 소견서)','보험회사가 계약심사(언더라이팅) 과정에서 청약자의 기왕증 또는 건강 상태를 심층 파악하기 위해 해당 의사 또는 의료기관에 직접 요청하는 서면 소견서. 청약서 및 건강진단 결과만으로 위험 판단이 불충분할 때 추가 심사 자료로 활용된다. 피보험자 동의를 전제로 하며, 주치의·진료 의사가 치료 경위·현재 상태·예후 등을 기재한다. 국내외 생명보험 언더라이팅 실무에서 광범위하게 사용된다.','인수',array['APS','주치의소견서','언더라이팅','계약심사','의무기록','인수심사'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 민영건강보험의 언더라이팅 선진화 방안(re2003-01) — kiri.or.kr 원문 PDF 확인','ai_draft','medium','admin'),
('term','표준화(Standardization) 인수 — 재심사(Re-underwriting)','최초 인수 시 조건부 승인(할증·부담보 등)으로 처리된 계약에 대해 일정 기간 경과 후 또는 피보험자의 건강 상태 변화를 이유로 표준체 조건으로 재전환을 심사하는 절차. 생명보험 실무에서는 계약자가 병력 완치·관해 확인서류를 제출하면 보험회사가 재심사를 진행한다. 상법상 별도 명문 규정은 없으나 보험업감독업무시행세칙 [별표14] 표준사업방법서 및 각 사 내규에서 운용한다.','인수',array['재심사','표준화인수','할증해제','부담보해제','조건부승인'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 [별표14] 표준사업방법서(금융감독원, law.go.kr 수록); 보험연구원(KIRI) 민영건강보험의 언더라이팅 선진화 방안(re2003-01)','ai_draft','medium','admin'),
('term','고위험 청약 특별인수심사(Special Underwriting for High-risk Applications)','보험가입금액이 일정 기준을 초과하거나 단기간 집중 가입, 역선택 징후 등 고위험 신호가 있는 청약 건에 대해 일반 심사보다 강화된 절차를 적용하는 제도. 생명보험협회·손해보험협회 「중복·과다 보험가입 방지 인수심사 가이드라인」(2023.9.1 시행)에 의거, 보험회사는 피보험자의 연령대별 소득상실 추정액 대비 배수를 고려해 인수 기준을 마련한다. 취약계층에 대한 담보액 감액 인수 조항도 포함된다.','인수',array['고위험청약','특별인수심사','역선택방지','집중가입','인수기준강화'],'cycle2_supp','cycle2_supp','생명보험협회·손해보험협회 「중복·과다 보험가입 방지 인수심사 가이드라인」(2023.9.1 시행); KIRI 보험법 동향 15호(kiri.or.kr 수록)','ai_draft','high','admin'),
('term','사전언더라이팅(Pre-underwriting / Pre-screening)','청약서 공식 접수·서명 이전에 고객이 입력한 건강 고지 내용을 기반으로 보험회사가 사전에 인수 가능 여부 및 예상 조건을 안내하는 절차. 청약 후 심사 지연 및 사후 거절에 따른 소비자 불만을 줄이기 위해 도입됐으며, 한화생명·iM라이프 등 국내 보험사들이 AI·디지털 기술과 결합해 즉시 결과를 제공하는 방향으로 도입·확대하고 있다. 청약 전 단계이므로 계약 효력은 발생하지 않는다.','인수',array['사전언더라이팅','pre-screening','청약전심사','AI언더라이팅','인수가능여부'],'cycle2_supp','cycle2_supp','한국보험신문 「보험사, 고객 편의 위한 사전·가상 언더라이팅 도입 경쟁」(insnews.co.kr); 메트로서울 「보험심사 더 간단하게」(metroseoul.co.kr, 2024.5)','ai_draft','medium','admin'),
('term','계약 후 알릴 의무(통지의무) 위반과 보험료 비례 정산','피보험자가 직업·직무 변경 등 위험 증가 사실을 보험회사에 즉시 통지하지 않은 경우(상법 제652조), 보험회사는 사고 발생 시 변경 전 요율과 변경 후 요율의 비율에 따라 보험금을 비례 지급할 수 있다(약관 규정에 따름). 또한 통지 접수 후 1개월 이내에 보험료 증액을 청구하거나 계약을 해지할 수 있다. 직업 변경 미통지가 가장 빈번한 분쟁 유형이며, 금감원 분쟁조정 선례가 다수 존재한다.','인수',array['통지의무위반','계약후알릴의무','보험료비례정산','직업변경통지','상법652조'],'cycle2_supp','cycle2_supp','상법 제652조(위험변경증가의 통지와 계약해지) — 국가법령정보센터(law.go.kr) 조문 및 판례 확인; 금감원 파인(fine.fss.or.kr) 보험 기본사항 안내','ai_draft','high','admin'),
('term','위험보유한도(Retention Limit)와 최적 출재비율','보험회사가 단일 위험(1건)에 대해 자기 부담으로 보유할 수 있는 최대 금액. 이를 초과하는 위험은 재보험으로 출재한다. 보험업감독규정(금융감독원 소관)에서 재보험 관리기준을 정하고 있으며, 보유한도 초과 위험을 방치하면 RBC(지급여력비율)에 악영향을 미친다. 최적 출재비율은 재보험비용과 자기자본비용의 합이 최소화되는 지점에서 결정된다.','인수',array['위험보유한도','출재비율','자기보유한도','재보험관리기준','RBC'],'cycle2_supp','cycle2_supp','보험업감독규정(금융위원회 고시, law.go.kr 수록); KIRI 재보험 출재전략 연구(nre2019-1212, kiri.or.kr 원문 확인)','ai_draft','medium','admin'),
('term','임의재보험(Facultative Reinsurance)과 특약재보험(Treaty Reinsurance) 선택 기준','임의재보험은 원수보험계약 건별로 재보험자와 개별 협상하여 계약하는 방식으로, 특약재보험의 한도를 초과하거나 특수·거대 위험 인수 시 활용한다. 특약재보험은 사전 협약에 따라 일정 범위 내 모든 계약을 자동 출재한다. 언더라이팅 실무에서는 자동인수한도(Auto-bind limit) 이하는 특약, 초과분은 임의재보험 또는 거절 처리하는 병행 운용이 일반적이다.','인수',array['임의재보험','특약재보험','자동인수한도','출재방법','거대위험'],'cycle2_supp','cycle2_supp','KIRI 재보험 이해 및 현황(nre2019-1212) — kiri.or.kr PDF 원문 확인; KIRI KiRi Weekly 손해보험의 이해 6: 위험의 보유와 재보험(2012.6, kiri.or.kr 수록)','ai_draft','high','admin'),
('term','초과손해액재보험(Excess of Loss Reinsurance, XL)','비비례재보험의 핵심 형태로, 출재사의 보유한도(Retention)를 초과하는 손해액에 대해 재보험자가 책임지는 구조. ''위험당 XL(Working XL)'', ''사고당 XL(Catastrophe XL)'', ''초과손해율 XL(Stop Loss)'' 등으로 세분된다. 거대재해 리스크 분산에 효과적이며, 특약재보험의 비비례 방식으로 운용된다. 손보사 대형화재·풍수해 대비 필수 수단이다.','인수',array['초과손해액재보험','XL재보험','비비례재보험','CatXL','거대재해분산'],'cycle2_supp','cycle2_supp','KIRI 재보험 이해 및 현황(nre2019-1212) 부록 Stop Loss Reinsurance 이론(kiri.or.kr PDF 직접 확인); KIRI KiRi Weekly 손해보험의 이해 6: 위험의 보유와 재보험(2012.6)','ai_draft','high','admin'),
('term','할증보험료 산출 — 여명(餘命) 기준 방식','표준미달체(Substandard Risk)에 대한 생명보험 할증 시, 피보험자의 잔여 기대여명이 동령 표준체보다 단축된 정도를 기준으로 추가보험료를 산출하는 계리 방식. 사망률을 일정 배율(예: 150%, 200%)로 할증하거나 가입나이를 연장(Age Rating)하는 방법이 있다. 생명보험 요율산출 기준서 및 보험료·책임준비금 산출방법서(보험업법 시행령 제7조의2)에서 요율 산출 원칙을 정한다.','인수',array['표준미달체할증','여명기준','사망률할증','연령할인할증','계리언더라이팅'],'cycle2_supp','cycle2_supp','보험업법 시행령 제7조의2(보험료 및 책임준비금 산출방법) — 국가법령정보센터(law.go.kr); 보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원)','ai_draft','high','admin'),
('term','혼합 조건부 인수(Combined Conditional Acceptance)','인수 시 할증보험료 부과와 특정 신체부위·질병 부담보를 동시에 적용하는 인수 결과 유형. 단순 할증이나 단순 부담보만으로는 위험을 충분히 반영하기 어려운 복합 병력 청약자에게 적용한다. 생명보험 표준사업방법서(보험업감독업무시행세칙 별표14)에서 조건부 승낙 유형으로 규정하며, 언더라이터는 할증률과 부담보 부위·기간을 개별 결정한다.','인수',array['혼합조건부인수','할증부담보병행','복합병력','조건부승낙유형','언더라이터결정'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원 보험심사팀) — 국가법령정보센터(law.go.kr)','ai_draft','high','admin'),
('term','신용정보 활용 언더라이팅(Credit-based Underwriting)','보험회사가 피보험자의 신용정보(보험계약 정보, 보험금 지급 이력 등)를 한국신용정보원에서 조회하여 인수심사에 활용하는 방식. 동의를 전제로 하며, 과거 보험사기 이력, 단기간 다수 가입 이력, 보험금 청구 집중도 등을 파악하는 데 사용된다. 신용정보의 이용 및 보호에 관한 법률(신용정보법)·보험업법에 근거한다.','인수',array['신용정보언더라이팅','보험신용정보','한국신용정보원','인수심사정보조회','보험사기이력'],'cycle2_supp','cycle2_supp','신용정보의 이용 및 보호에 관한 법률 — 국가법령정보센터(law.go.kr); 한국신용정보원 공식 안내(kcredit.or.kr)','ai_draft','high','admin'),
('term','계약전 알릴 의무 고지 범위 — 표준·건강·간편고지 3유형','보험 청약서의 고지 항목 범위에 따라 세 유형으로 분류된다. 1) 표준고지형: 일반적 청약서로 3개월 이내 진단·투약, 1년 이내 추가검사, 5년 이내 입원·수술·30일 이상 투약, 5년 이내 10대 질병 등을 고지. 2) 건강고지형: 표준형보다 고지 항목 확대. 3) 간편고지형(유병자보험): 고지 항목 대폭 축소. 보험업감독업무시행세칙 별표14에서 고지사항 기준을 규정한다.','인수',array['계약전알릴의무','고지범위','표준고지','간편고지','건강고지','별표14'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원) — 국가법령정보센터(law.go.kr); 금감원 금융꿀팁 보험계약 전 알릴의무 안내','ai_draft','medium','admin'),
('term','태아 주수별 인수 제한(Fetal Gestational Age Underwriting Limit)','태아보험(출생 전 가입 보험)의 인수 가능 주수 상한을 정한 기준. 손해보험은 임신 직후부터 22주(일부 23주) 이내, 생명보험은 통상 임신 16주부터 22주 이내 가입을 허용한다. 기형아 검사(NT 검사, 정밀초음파) 결과에 이상 소견이 발견되기 전에 가입해야 선천성 질환 담보를 확보할 수 있다. 쌍둥이 임신, 인공수정 임신의 경우 별도 서류 심사를 거친다.','인수',array['태아보험인수','임신주수제한','태아특약','선천성질환담보','기형아검사전가입'],'cycle2_supp','cycle2_supp','찾기쉬운 생활법령정보(easylaw.go.kr) 임산부·태아보험 가입 항목','ai_draft','medium','admin'),
('term','비례보상(Proportional Compensation) — 통지의무 위반 시','피보험자가 위험 증가 사실을 통지하지 않아 보험료가 과소납부된 상태에서 보험사고가 발생한 경우, 보험회사가 실제 납부 보험료와 납부했어야 할 보험료의 비율에 따라 보험금을 지급하는 방식. 상법 제652조 통지의무 위반의 효과로 계약 해지 대신 보험금 비례 감액이 적용되는 실무 처리 방식이다. 직업 위험 급수 변경 미통지 분쟁에서 빈번히 적용된다.','보장',array['비례보상','통지의무위반','보험금감액','직업변경비례지급','상법652조'],'cycle2_supp','cycle2_supp','상법 제652조(위험변경증가의 통지와 계약해지) — 국가법령정보센터(law.go.kr); 대법원 판례속보 통지의무 위반 관련 사건(scourt.go.kr)','ai_draft','high','admin'),
('term','출재사(Ceding Company)와 수재사(Assuming/Reinsuring Company)','출재사는 자신의 원수보험계약 위험을 재보험자에게 이전하는 보험회사이며, 수재사(재보험회사)는 그 위험을 인수하는 회사이다. 출재사가 지급하는 재보험료(Reinsurance Premium)에서 수재사가 환급하는 재보험수수료(Ceding Commission)를 차감한 순비용이 출재비용이다. 국내 보험업감독규정에서 출재·수재 비율과 재보험 계약 체결 기준을 정한다.','인수',array['출재사','수재사','재보험료','재보험수수료','출재비용'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 재보험 이해 및 현황(nre2019-1212) — kiri.or.kr','ai_draft','high','admin'),
('term','포트폴리오 언더라이팅(Portfolio Underwriting) — 위험집중 관리','개별 계약 단위 심사를 넘어, 보험회사 전체 계약 포트폴리오 차원에서 특정 지역·업종·피보험자 특성에 위험이 집중되지 않도록 관리하는 언더라이팅 전략. 지역 집중(Geographical Concentration), 업종 집중, 특정 연령층 집중 등을 모니터링한다. 손해보험 화재·자연재해 분야에서 특히 중요하며, 위험집중 지역 신규 인수 제한 결정도 이에 해당한다.','인수',array['포트폴리오언더라이팅','위험집중관리','지역집중','언더라이팅전략','손해보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 일반손해보험과 언더라이팅 연구(josa_15_07_02) — kiri.or.kr','ai_draft','medium','admin'),
('term','계약적부확인(Post-issue Underwriting / Field Underwriting Audit)','보험계약 승낙 후 계약의 실질적 유효성과 청약서 기재 내용의 진실성을 현장 또는 서류 조사를 통해 검증하는 절차. 고액계약, 단기 집중가입, 피보험자 미면접 계약 등에서 실시하며, 모럴해저드 및 보험사기 방지가 주목적이다. 생명보험 실무에서는 계약 체결 직후 현장 확인(Field Inspection)을 수행하기도 한다. 보험업감독업무시행세칙 표준사업방법서에 관련 기준이 반영된다.','인수',array['계약적부확인','사후언더라이팅','현장조사','보험사기방지','고액계약심사'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 일반손해보험과 언더라이팅 연구(josa_15_07_02) — kiri.or.kr; 보험업감독업무시행세칙(금융감독원) — 국가법령정보센터(law.go.kr)','ai_draft','high','admin'),
('term','부담보 기간 유형 — 전기간·한시·특정사고 부담보','부담보 처리 방식은 적용 기간과 범위에 따라 세분된다. 1) 전기간 부담보: 계약 기간 전체에 걸쳐 특정 부위·질병 보장 제외. 2) 한시(限時) 부담보: 일정 기간(예: 1년, 2년)만 부담보 적용 후 표준체 전환. 3) 특정사고 부담보: 특정 원인(예: 기왕증으로 인한 재발)에 한해 부담보. 생명보험 표준사업방법서 및 각 보험사 인수지침에서 유형별 적용 기준을 정한다.','인수',array['전기간부담보','한시부담보','특정사고부담보','부담보유형','인수조건'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원) — 국가법령정보센터(law.go.kr)','ai_draft','high','admin'),
('term','인수 거절 사유 통보 의무와 소비자 권리','보험회사가 청약을 거절하는 경우, 상법 제638조의2에 따라 보험료 납입과 함께 청약을 받은 날로부터 30일 이내에 승낙 또는 거절 통보를 발송해야 한다. 30일 내 미통보 시 승낙 간주. 다만 ''거절 시 사유를 구체적으로 알릴 의무''는 동 조항에 명시되어 있지 않으며, 보험업감독규정상 명시적 의무 조항도 검색 결과에서 확인되지 않는다. 거절 이유를 확인하려는 소비자는 금융소비자보호법 제28조 제3항(자료의 기록 및 유지·관리, 자료열람요구권)을 근거로 분쟁조정 또는 소송 목적의 자료 열람을 요구할 수 있다. 단, 동 조항은 모든 청약 심사 자료 열람을 포괄적으로 보장하는 규정이 아니며 ''분쟁조정 또는 소송 수행 등 권리구제 목적''으로 한정된다.','민원',array['인수거절사유통보','거절사유고지의무','소비자권리','분쟁조정','자료열람요구'],'cycle2_supp','cycle2_supp','상법 제638조의2(보험계약의 성립) — 국가법령정보센터(law.go.kr); 금융소비자 보호에 관한 법률 제28조 제3항(자료열람요구권) — 국가법령정보센터','ai_draft','medium','admin'),
('term','개인정보·건강정보 수집·활용 동의와 철회 — 보험 계약심사','보험회사는 계약심사를 위해 피보험자의 민감정보(건강 정보, 진료 기록 등)를 수집할 때 별도의 명시적 동의를 받아야 한다(개인정보 보호법 제23조, 신용정보법). 동의 철회 시 해당 정보는 원칙적으로 파기되나, 계약 유지를 위해 필요한 최소 정보는 법정 보존기간 동안 보관된다. 보험사는 개인정보처리방침에 건강정보 수집·이용·제공 현황을 공개해야 한다.','계약',array['건강정보동의','민감정보수집','동의철회','개인정보보호법23조','계약심사정보'],'cycle2_supp','cycle2_supp','개인정보 보호법 제23조(민감정보의 처리 제한) — 국가법령정보센터(law.go.kr); KIRI 보험연구원 인슈어테크 발전에 따른 보험신용정보 보호 및 활용(kiri.or.kr)','ai_draft','high','admin'),
('term','자동인수한도(Auto-bind Limit / Automatic Binding Limit)','재보험 특약 계약에서 원수보험사가 재보험사의 별도 승인 없이 자동으로 출재할 수 있는 1건당 최대 책임금액. 이 한도 이내 계약은 특약 조건에 따라 자동 처리되고, 초과분은 임의재보험 협상 또는 언더라이터 직접 심사가 필요하다. 국내 보험업감독규정에서 재보험 관리기준의 일환으로 자동인수한도 설정·관리를 규정한다.','인수',array['자동인수한도','auto-bind','특약재보험한도','재보험관리','언더라이터승인'],'cycle2_supp','cycle2_supp','보험업감독규정(국가법령정보센터 law.go.kr) — 재보험 관리기준 관련 별표; 보험연구원(KIRI) 재보험 관련 연구 자료(kiri.or.kr)','ai_draft','medium','admin'),
('term','일반손해보험 개별물건 요율(Individual Risk Rating)','공장·특수건물 등 기업성 손해보험 계약에서 동질 집단 통계 기반 참조요율 적용이 어려운 경우, 언더라이터가 개별 물건의 구조·소방설비·위험물 보관 여부·손해방지 활동 등을 직접 평가하여 요율을 산출하는 방식. 보험개발원 참조순보험요율을 기준으로 가감요율을 적용한다. 보험업감독규정 제6-4조에서 요율 산출 원칙을 정한다.','인수',array['개별물건요율','기업성손해보험','특수건물','공장언더라이팅','요율산출'],'cycle2_supp','cycle2_supp','보험업감독규정 제6-4조(보험요율 산출원칙) — 국가법령정보센터(law.go.kr); 보험연구원(KIRI) 일반손해보험 언더라이팅 관련 연구자료(kiri.or.kr)','ai_draft','high','admin'),
('term','독립책임액 방식(비례보상 계산법)','실손의료보험 등 손해보험에서 다수 계약이 존재할 때 각 보험사의 지급 책임을 산정하는 방식. 각 계약이 ''단독으로 존재했다면 지급했을 금액(독립책임액)''을 먼저 각각 산출한 뒤, 그 합산액 대비 각 독립책임액의 비율에 따라 실제 손해액을 나누어 보상한다. 상법 제672조(중복보험) 적용 시 주요 계산법 중 하나로 사용되며, 보험사마다 공제기준·한도가 다를 때 각 계약을 별개로 계산하므로 실제 수령액이 단순 비율과 다를 수 있다.','보장',array['독립책임액','비례보상 계산','중복보험 정산','상법672조','다수계약 보상'],'cycle2_supp','cycle2_supp','상법 제672조(중복보험) — 국가법령정보센터(law.go.kr); 클레임손해사정 중복보험 보상방법 해설(claimcare.co.kr)','ai_draft','high','admin'),
('term','4세대 실손보험 비급여 할인·할증 등급제(1~5등급)','2024년 7월 1일부터 시행된 4세대 실손보험의 비급여 보험료 차등제. 갱신 전 1년간 비급여 보험금 수령액에 따라 5단계로 구분한다. 1등급(수령 0원)은 약 5% 할인, 2등급(100만원 미만)은 유지, 3등급(100만원 이상~150만원 미만)은 +100%, 4등급(150만원~300만원)은 +200%, 5등급(300만원 이상)은 +300% 할증. 계약 해당일 3개월 전 말일부터 직전 1년 지급실적 기준으로 산정. 보험사 앱·홈페이지에서 등급 조회 가능. 산정특례 대상 질환(암·심장·뇌혈관·희귀난치) 및 노인장기요양보험법상 장기요양 1·2등급 판정자의 의료비는 할증 등급 산정에서 제외된다.','보장',array['비급여 할인할증','4세대 실손 등급제','비급여 차등보험료','실손 1~5등급'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 ''24.7.1일부터 4세대 실손의료보험 비급여 이용량에 따라 보험료 할인·할증 적용''(fsc.go.kr/po010101/82406)','ai_draft','high','admin'),
('term','실손보험 계약전환 시 무사고 할인 승계','1~3세대 실손보험 가입자가 4세대로 계약전환 시 기존 계약의 무사고 기간도 인정받아 보험료 할인 혜택이 승계된다. 4세대 기준 직전 2년 무사고 시 비급여 특약 보험료의 10% 할인이 적용된다(별도의 비급여 차등제 할인 약 5%와 중복 적용 가능). 전환 후 3개월 이내는 보험금 지급사유 발생 여부와 관계없이 철회 가능하고, 3개월 초과~6개월 이내는 보험금 수령이 없을 경우 철회하여 원계약으로 복귀할 수 있다(무심사 전환 + 철회제도). 단, 전환 전 계약의 보장내용·보험료는 되돌아가므로 전환 전 충분한 비교 검토가 필요.','계약',array['실손 계약전환','무사고 할인 승계','실손 4세대 전환','무심사전환','전환 철회'],'cycle2_supp','cycle2_supp','손해보험협회 실손 전환제도 안내(kpub.knia.or.kr/productDisc/lostHealth/lostHealthMinsInsIntro.do); DB손해보험 4세대 실손 계약전환 할인제도 시행 안내(idbins.com)','ai_draft','medium','admin'),
('term','실손24(실손보험 청구 전산화)','보험업법 개정(2023년 10월 24일 공포, 법률 제19780호)으로 도입된 실손의료보험 청구 전산화 시스템. 요양기관이 청구에 필요한 서류(진료비 영수증·세부내역서 등)를 보험개발원(전송대행기관)을 통해 보험사에 전자적으로 전송한다. 1단계(2024년 10월 25일): 병원급 이상·보건소(약 0.8만개) 대상. 2단계(2025년 10월 25일): 의원·약국까지 확대, 전국 약 10.5만 요양기관 대상. 소비자가 청구하지 않은 진료 정보는 전송 불가(목적 외 정보 집중 금지).','민원',array['실손24','실손보험 청구 전산화','청구간소화법','보험업법 개정','전송대행기관'],'cycle2_supp','cycle2_supp','보험업법 제102조의10 이하(국가법령정보센터 law.go.kr); 금융위원회 보도자료 ''실손보험 청구 전산화 확대 시행''(fsc.go.kr/no010101/85456)','ai_draft','high','admin'),
('term','5세대 실손보험(중증 비급여 특약1·비중증 비급여 특약2 분리 구조)','2026년 5월 6일 출시된 5세대 실손의료보험. 비급여를 중증(특약1)과 비중증(특약2)으로 분리 보장. 특약1(중증 비급여): 산정특례 대상 질환(암·심장·뇌혈관·희귀난치 등) 관련 비급여, 자기부담 30%, 연간 5000만원 한도. 특약2(비중증 비급여): 도수치료·비급여주사 등, 자기부담 50%(통원 시 50%+5만원), 연간 1000만원 한도. 4세대 대비 보험료 약 30% 저렴. 중증 비급여에는 연간 자기부담 상한 500만원 신설로 중증 환자 의료비 과부담 방지.','보장',array['5세대 실손보험','중증 비급여 특약','비중증 비급여 특약','실손보험 개편 2026','비급여 자기부담 50%'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 5세대 실손 출시(fsc.go.kr/no010101/86059); 금융위원회 5세대 실손 상세 보도자료(fsc.go.kr/no010101/86831)','ai_draft','high','admin'),
('term','통원 합산 한도(외래+처방조제 1회 20만원, 연간 180회)','4세대 표준 실손의료보험 기준, 통원의료비는 외래와 처방조제비를 합산하여 1회당 20만원 한도로 보장되며, 입·통원 합산 연간 5000만원을 한도로 한다. 통원 횟수는 연간 180회까지. 같은 날 동일 의료기관에서 외래 진료와 처방조제를 함께 받은 경우 처방일자 기준으로 1회로 합산 처리된다. 공제금액은 종별로 차등(병·의원: 1만원과 의료비의 20% 중 큰 금액; 상급종합·종합병원: 2만원과 20% 중 큰 금액).','보장',array['통원 합산 한도','외래 처방 1회','실손 통원 20만원','연간 180회','통원 공제금액'],'cycle2_supp','cycle2_supp','손해보험협회 실손의료보험(4세대) 표준 공시(kpub.knia.or.kr/productDisc/lostHealth/lostHealth4thStandard.do)','ai_draft','high','admin'),
('term','비급여 의료행위 표준코드(HIRA 비급여 코드 체계)','건강보험심사평가원(HIRA)이 비급여 의료행위 및 치료재료에 부여하는 표준 분류 코드. 비급여 항목 코드를 표준화하여 의료기관 간 비교공시를 가능하게 한다. 실손보험 청구 전산화(실손24)에서 요양기관이 서류를 전송할 때 이 코드가 활용된다. 비급여 진료비용 등의 보고 및 공개에 관한 기준(보건복지부 고시)에 의해 병원급 이상 의료기관은 지정된 항목을 심사평가원에 보고·공개 의무가 있다. 공개 항목 수는 급여 전환 및 삭제 등에 따라 변동되며(과거 616항목에서 현재 578항목 등으로 변경), source 확인 시점의 최신 고시를 기준으로 적용한다.','보장',array['비급여 코드','HIRA 비급여 분류코드','비급여 표준코드','비급여 진료비 공시','심사평가원 비급여'],'cycle2_supp','cycle2_supp','건강보험심사평가원 비급여 의료행위 및 치료재료 코드 표준화 연구(repository.hira.or.kr); 국가법령정보센터 비급여 진료비용 등의 보고 및 공개에 관한 기준(law.go.kr); HIRA 비급여 진료비 정보 안내(hira.or.kr/npay)','ai_draft','medium','admin'),
('term','비급여 진료비 고지 의무(의료법상 사전 설명·게시 의무)','의료법 제45조 및 ''비급여 진료비용 등의 고지 지침''(보건복지부 고시 제2023-192호, 2023.10.25. 시행)에 따라 의료기관은 비급여 대상 제공 전 환자에게 항목·가격을 직접 설명해야 하며, 원내 비치·인터넷 홈페이지 게시 의무가 있다. 병원급 이상은 HIRA 비급여 진료비 정보 포털을 통해 연간 비급여 진료비 현황을 공개한다. 보험사는 이 공개 데이터를 활용해 비급여 보험료 할인·할증의 기초 자료로 활용한다.','보장',array['비급여 진료비 고지 의무','비급여 사전 설명','의료법 비급여 게시','비급여 진료비 공개','HIRA 비급여 포털'],'cycle2_supp','cycle2_supp','의료법 제45조(국가법령정보센터 law.go.kr); 보건복지부 비급여 진료비용 등의 고지 지침(보건복지부 고시 제2023-192호, law.go.kr); HIRA 비급여 정보 포털(hira.or.kr)','ai_draft','high','admin'),
('term','피보험자의 손해사정사 독립 선임권','보험업법 제185조 및 시행령에 따라, 보험회사 소속 손해사정사의 사정 결과에 불복하는 보험계약자·피보험자는 독립 손해사정사를 별도로 선임할 수 있다. 선임 가능 요건: 1) 보험회사 손해사정 결과에 불복하는 경우 2) 보험사고 통보 후 7영업일 경과에도 손해사정 착수 없는 경우(2023년 3영업일에서 10영업일로 확대 개정). 보험회사는 금융위원회가 정한 선임 동의기준 충족 시 반드시 동의해야 한다. 2024년 보험업법 개정(공포 2024.2.6., 시행 2024.8.7.)으로 보험회사 소속 손해사정사 평가 기준에 보험금 삭감 유도 지표 사용 금지 추가.','민원',array['손해사정사 선임권','독립 손해사정사','손해사정 불복','보험업법 185조','손해사정 이의'],'cycle2_supp','cycle2_supp','보험업법 제185조(국가법령정보센터 law.go.kr); 금융위원회 ''보험권의 손해사정 관행이 개선됩니다'' 보도자료(fsc.go.kr); 손해사정 업무위탁 및 손해사정사 선임 등에 관한 모범규준(kcaca.or.kr)','ai_draft','medium','admin'),
('term','본인부담상한제(건강보험 연간 본인부담 상한액 초과 환급)','국민건강보험법 시행령 제19조에 따라 건강보험 가입자가 연간 부담한 요양급여 본인부담금 총액이 소득분위별 상한액을 초과하면 건강보험공단이 초과분을 사후 환급하는 제도. 소득 1~10분위 구간별로 상한액이 다르며(2023년 기준 87만~780만원), 낮은 소득분위일수록 상한액이 낮아 더 많은 환급을 받는다. 비급여·전액 본인부담·선별급여·임플란트·상급병실 2~3인실은 상한액 산정에서 제외. 실손보험과 중복 적용 가능.','보장',array['본인부담상한제','건강보험 상한액 환급','소득분위별 상한','연간 의료비 환급','국민건강보험 환급'],'cycle2_supp','cycle2_supp','국민건강보험공단 본인부담액상한제 안내(nhis.or.kr); 국민건강보험법 시행령 제19조(law.go.kr); 보건복지부 2023년도 본인부담상한액 초과의료비 지급절차 개시 보도자료(mohw.go.kr)','ai_draft','high','admin'),
('term','국민건강보험공단 구상권(제3자 행위에 의한 보험급여 구상)','국민건강보험법 제58조에 따라 건강보험공단은 제3자(교통사고 가해자 등)의 행위로 발생한 보험사고에 급여를 제공한 경우, 급여한 비용 한도 내에서 제3자에 대한 구상권을 취득한다. 구상권 취득 시기는 피보험자가 요양기관에서 치료를 받은 시점. 민간 손해보험사의 보험자대위(상법 제682조)와 유사하나 주체와 근거 법령이 다르다. 대법원 2025.6.5. 중요판결에서 공단 구상권 취득 시기를 재확인.','보장',array['건강보험공단 구상권','제3자 행위 보험급여','국민건강보험법 58조','보험자대위 구분','교통사고 구상권'],'cycle2_supp','cycle2_supp','국민건강보험법 제58조(국가법령정보센터 law.go.kr); 대법원 2025.6.5. 선고 중요판결(scourt.go.kr 판례속보)','ai_draft','high','admin'),
('term','실화책임에 관한 법률(경과실 실화 손해배상 경감)','경과실로 화재를 발생시킨 자(실화자)의 손해배상액을 법원이 감액할 수 있도록 한 법률(법률 제9648호, 2009.5.8. 전면개정). 민법의 일반 불법행위 책임을 그대로 적용하면 실화자에게 과도한 부담이 생길 수 있어 재판상 감액을 허용. 단, 특수건물 소유자는 ''화재로 인한 재해보상과 보험가입에 관한 법률''에 따라 경과실에도 무과실 책임 수준의 배상책임 보험 가입 의무가 있다. 보험설계 시 화재보험 배상책임 특약 가입 필요성의 근거 법령.','보장',array['실화책임법','경과실 화재 배상','실화 손해배상 경감','화재보험 배상책임','특수건물 의무보험'],'cycle2_supp','cycle2_supp','실화책임에 관한 법률(국가법령정보센터 law.go.kr); 화재로 인한 재해보상과 보험가입에 관한 법률(law.go.kr); 법제처 찾기쉬운 생활법령 화재보험(easylaw.go.kr)','ai_draft','high','admin'),
('term','특수건물 신체손해배상 특약부 화재보험 의무가입','''화재로 인한 재해보상과 보험가입에 관한 법률(화재재해보상법)''에 따라 법령에 열거된 특수건물 소유자는 의무적으로 신체손해배상 특약부 화재보험에 가입해야 한다. 특수건물 범위는 건물 용도·규모별로 다양하며(국·공유 건물 1,000㎡ 이상, 학원 2,000㎡ 이상, 병원·호텔·공연장·학교·공장·16층 이상 아파트 등 3,000㎡ 이상 등 시행령 제2조 별표 기준). 특수건물 화재로 타인이 사망·부상을 입으면 과실 유무와 관계없이 법정 보험금액 범위에서 손해 배상 책임을 지며, 미가입 시 과태료 1,000만원 이하 부과 가능. 일반 화재보험(임의 가입)과 구별되는 강제보험.','계약',array['특수건물 의무보험','신체손해배상 특약부 화재보험','화재재해보상법','특수건물 강제보험','과실 무관 배상'],'cycle2_supp','cycle2_supp','화재로 인한 재해보상과 보험가입에 관한 법률 및 시행령(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 화재보험 의무가입(easylaw.go.kr); 금융위원회 화재재해보상법 개정 안내(fsc.go.kr)','ai_draft','medium','admin'),
('term','다중이용업소 화재배상책임보험(의무가입)','''다중이용업소의 안전관리에 관한 특별법''에 따라 노래방·PC방·음식점 등 다중이용업소 업주는 화재배상책임보험에 의무 가입해야 한다. 인명피해 사망 1인당 최대 1억5천만원(실손해액이 2천만원 미만이면 2천만원 최저보장), 재산피해 사고 1건당 최대 10억원 보상. 재난 및 안전관리 기본법 제76조의5에 따른 재난배상책임보험 의무가입 대상 20개 업종과 일부 중복 적용. 미가입 시 행정처분(영업정지 등).','계약',array['다중이용업소 화재배상책임보험','의무배상책임보험','재난배상책임보험','화재배상 강제보험','다중이용업소 의무가입'],'cycle2_supp','cycle2_supp','다중이용업소의 안전관리에 관한 특별법(국가법령정보센터 law.go.kr); 행정안전부 재난배상책임보험 운영(mois.go.kr); 재난안전의무보험별 소개(ins24.go.kr)','ai_draft','high','admin'),
('term','의료사고 분쟁조정 절차(한국의료분쟁조정중재원)','''의료사고 피해구제 및 의료분쟁 조정 등에 관한 법률''에 따라 운영되는 한국의료분쟁조정중재원(2012년 설립)을 통한 의료분쟁 해결 절차. 환자·의료기관 일방 신청으로 개시되며, 조정 90일(최대 120일) 내에 처리. 의료사고 조사·감정 후 조정기일에 합의로 조정조서 작성(성립) 또는 조정결정 후 쌍방 동의로 성립. 조정안 20일 내 수락 의사표시 없으면 불성립. 신청 시효는 행위 종료일로부터 10년, 손해·가해자 안 날로부터 3년.','민원',array['의료분쟁 조정','의료분쟁조정중재원','의료사고 배상','의료분쟁 절차','의료사고 피해구제법'],'cycle2_supp','cycle2_supp','의료사고 피해구제 및 의료분쟁 조정 등에 관한 법률(국가법령정보센터 law.go.kr); 한국의료분쟁조정중재원(k-medi.or.kr); 법제처 찾기쉬운 생활법령 의료분쟁(easylaw.go.kr)','ai_draft','high','admin'),
('term','영업배상책임보험(시설·업무 수행 중 제3자 신체·재물 손해 담보)','피보험자가 영업활동(시설 관리·업무 수행) 중 우연한 사고로 제3자에게 신체적 손해나 재물 손해를 입혀 법률상 손해배상책임을 질 때 보험사가 보상하는 손해보험. 임의보험이며 재난배상책임보험보다 보장 범위가 넓다. 하위 종류로는 시설소유관리자배상책임, 생산물배상책임(제조물책임), 개인(일상생활)배상책임, 의료과실배상책임 등이 있다. 보험업법상 손해보험 종목으로 금융위원회가 인가.','보장',array['영업배상책임보험','시설배상책임','생산물배상책임','일상생활배상책임','손해보험 배상책임'],'cycle2_supp','cycle2_supp','법제처 찾기쉬운 생활법령 책임보험(easylaw.go.kr); 손해보험협회 교육센터(edu.knia.or.kr)','ai_draft','high','admin'),
('term','보험계약 부활(효력회복) 절차와 요건(상법 제650조의2)','상법 제650조의2에 따라 보험료 미납으로 해지된 보험계약이 해지환급금 미지급 상태인 경우, 보험계약자는 해지일로부터 3년 이내에 연체 보험료와 이자(평균공시이율+1% 이내)를 납입하고 부활(효력회복)을 청약할 수 있다. 보험회사는 부활 청약 시 다시 심사(고지의무 재적용)하며 승낙 여부를 결정한다. ''자동 실효 약관''(최고 없이 자동 해지)은 상법 제650조·663조 위반으로 무효(대법원 판례).','계약',array['보험계약 부활','효력회복','상법 650조의2','실효 부활 조건','연체보험료 납입'],'cycle2_supp','cycle2_supp','상법 제650조의2(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 보험계약 효력회복(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=526); 보험연구원 주간이슈(kiri.or.kr/PDF/weeklytrend/20240930/trend20240930_3.pdf)','ai_draft','high','admin'),
('term','실손보험 청구서류 표준화(진단서·세부내역서·영수증 기준)','2010년 4월 1일 표준화, 2014년 1월 1일 간소화된 실손의료보험금 청구서류 기준. 입원의료비 청구 시 진단서+진료비 세부내역서+진료비 영수증이 기본이며, 50만원 이하 입원은 진단서 대신 진단명 및 입원기간이 포함된 입퇴원 확인서 또는 진료확인서로 대체 가능. 통원 청구 시 3만원 이하는 청구서+영수증만으로 가능, 3만원 초과~10만원 이하는 진료비 영수증+질병분류기호 기재 처방전으로 가능, 10만원 초과는 진단명 확인 가능 서류(처방전·소견서 등) 추가 제출. 2024년 10월 이후 실손24 전산청구를 선택하면 서류 없이 의료기관이 직접 전송.','민원',array['실손보험 청구서류','진단서 대체 서류','세부내역서','청구서류 표준화','실손 청구 방법'],'cycle2_supp','cycle2_supp','손해보험협회 실손의료보험금 청구서류 표준화 및 통일화 안내(consumer.knia.or.kr/m/consumer/insurance-guide/0202.do)','ai_draft','medium','admin'),
('term','보험금 지급 지연이자(보험업감독규정상 지연 이자율)','보험사가 보험금 청구서류 접수 후 법정 처리기한(통상 3영업일, 조사 필요 시 10영업일, 최대 30영업일) 내에 지급하지 않으면 지연 이자를 부담해야 한다. 지연 이자율은 상법 제54조의 상사법정이율(연 6%) 기준이 판례상 첫 기준으로 적용되며, 이후 소송 진행 시 소송촉진 등에 관한 특례법상 이율(연 12%)이 적용된다. 분쟁조정 신청 시 소멸시효가 중단된다. 단, 정당한 사유(사고 조사·소송 계속 중)가 있으면 지급 지연이 면책될 수 있다.','민원',array['보험금 지연이자','보험금 지급기한','지연 이자율','보험업감독규정','보험금 처리기한'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표15(law.go.kr); 법제처 찾기쉬운 생활법령 보험금 지급기한(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=526); 국가법령정보센터 판례(보험금 지연손해금, law.go.kr)','ai_draft','medium','admin'),
('term','실손보험 청구 시효(3년 소멸시효와 기산점)','실손의료보험금 청구권은 상법 제662조에 따라 3년의 소멸시효가 적용된다. 기산점은 보험사고 발생을 안 날이 아니라 보험금을 청구할 수 있는 날, 즉 진료비 지출일이 원칙. 분쟁조정 신청 시 소멸시효가 중단되며, 조정이 성립하지 않은 날로부터 다시 기산된다. 실무상 오래된 진료비도 3년 이내라면 소급 청구 가능하므로, 설계사가 가입자에게 미청구 진료비 내역 정리를 안내하는 것이 중요.','민원',array['실손보험 청구 소멸시효','보험금 청구 3년','소멸시효 기산점','미청구 보험금','상법 662조'],'cycle2_supp','cycle2_supp','상법 제662조(소멸시효, law.go.kr); 법제처 찾기쉬운 생활법령 분쟁조정 소멸시효 중단(easylaw.go.kr)','ai_draft','high','admin'),
('term','선별급여(예비급여) 본인부담 차등 구조','국민건강보험법상 치료 효과 불확실·경제성 불명확 의료행위를 급여와 비급여 사이 ''선별급여''로 분류하여 본인부담률을 30·50(60)·80·90%까지 높여 급여화한 제도. 보건복지부 고시로 항목별 본인부담률을 달리 지정한다. 실손보험에서는 선별급여 본인부담금도 급여 공제 대상이며, 본인부담상한제 산정에서는 제외된다. 추나요법 등 일부 항목이 선별급여로 편입된 바 있다.','보장',array['선별급여','예비급여','본인부담 차등','급여 비급여 중간','추나요법 선별급여'],'cycle2_supp','cycle2_supp','건강보험심사평가원 본인부담률 안내(hira.or.kr); 국민건강보험 요양급여의 기준에 관한 규칙 별표2 선별급여목록(law.go.kr/LSW/flDownload.do?flSeq=151430065)','ai_draft','medium','admin'),
('term','종신형 연금보험 비과세 요건 (보증기간 기대여명 이내)','세제비적격 연금보험이 보험차익 비과세 혜택을 받으려면 종신형 수령 시 1) 55세 이후 사망 시까지 연금 수령, 2) 연금 외 형태로 지급받지 않을 것, 3) 보증기간이 통계청 고시 성별·연령별 기대여명 연수 이내일 것, 4) 계약자=피보험자=수익자 동일, 5) 중도해지 불가 요건을 모두 충족해야 한다(소득세법 시행령 제25조). 기대여명보다 보증기간이 짧거나 같아야 하며, 초과 설정 시 비과세 요건 미충족으로 이자소득세(15.4%)가 과세된다.','세제',array['종신형연금','비과세요건','기대여명','보증기간','소득세법시행령25조','세제비적격'],'cycle2_supp','cycle2_supp','소득세법 시행령 제25조(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 연금보험 항목(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=2056)','ai_draft','high','admin'),
('term','연금수령한도 초과 인출 — 기타소득세 16.5% 분리과세','연금계좌(연금저축·IRP)에서 연금수령한도를 초과해 인출하면 초과분은 연금소득이 아닌 기타소득으로 분류돼 16.5%(지방소득세 포함) 세율로 분리과세된다(소득세법 제21조 제1항 제21호, 시행령 제40조의2). 연금수령한도 = 과세기간 개시일 현재 연금계좌 평가액 ÷ (11 - 연금수령연차) × 120%이며, 연금수령연차 11년 이상이면 한도 제한이 없다.','세제',array['연금수령한도','기타소득세','분리과세','16.5%','소득세법','연금외수령'],'cycle2_supp','cycle2_supp','소득세법 시행령 제40조의2(국가법령정보센터 law.go.kr); 국세청 연금소득의 범위(nts.go.kr/nts/cm/cntnts/cntntsView.do?mi=6449&cntntsId=7885)','ai_draft','high','admin'),
('term','이연퇴직소득 연금수령 시 퇴직소득세 감면 (10년 이내 30%, 11년 차 이후 40%)','퇴직소득을 IRP 등 연금계좌에 이전해 연금으로 분할 수령하면 이연퇴직소득에 대한 퇴직소득세가 감면된다. 연금수령 연차 10년 이하는 퇴직소득세율의 70% 납부(세금 30% 감면), 10년 초과는 60% 납부(40% 감면) 적용(소득세법 시행령 제202조의3). 이는 일시금 퇴직소득세에 비해 최대 40% 절세 효과이며, 과세이연과 분리돼 계산된다.','세제',array['이연퇴직소득','퇴직소득세감면','IRP연금수령','30%감면','40%감면','과세이연'],'cycle2_supp','cycle2_supp','소득세법 시행령 제202조의3(국가법령정보센터 law.go.kr); 국세청 퇴직소득세의 이연 안내(nts.go.kr/nts/cm/cntnts/cntntsView.do?mi=6602&cntntsId=7882)','ai_draft','medium','admin'),
('term','즉시연금 비과세 과세 논쟁 및 2013년 세법 개정 경과','즉시연금(목돈 일시납 후 즉시 연금 지급)은 2013년 2월 14일 이전 가입자에게는 금액 제한 없이 비과세였다. 이후 소득세법 시행령 제25조 개정으로 상속형 즉시연금은 납입보험료 1억 원 초과분에 대해 이자소득세 과세로 전환됐다. 종신형 즉시연금은 종신형 비과세 요건 충족 시 비과세 유지, 상속형은 1억 원 이하 비과세, 초과 시 이자소득세(15.4%) 과세(소득세법 시행령 제25조). 이 개정은 2013년 2월 15일부터 시행됐다.','세제',array['즉시연금','비과세과세논쟁','2013년세법개정','상속형즉시연금','1억원한도'],'cycle2_supp','cycle2_supp','소득세법 시행령 제25조(국가법령정보센터 law.go.kr); 보험연구원 ''연금보험의 비과세기준 개정 필요성과 시사점''(kiri.or.kr/report/downloadFile.do?docId=681)','ai_draft','medium','admin'),
('term','연금계좌 가입일 5년 경과 요건 — 이연퇴직소득 예외','연금계좌에서 연금수령으로 인정받으려면 가입일로부터 5년이 경과해야 하지만, 이연퇴직소득(퇴직소득이 직접 연금계좌로 입금된 금액)이 계좌에 있는 경우 5년 경과 요건이 면제된다(소득세법 시행령 제40조의2). 직장 퇴직 후 IRP에 수령된 퇴직금은 가입 즉시 연금 개시 요건을 충족할 수 있다.','세제',array['연금계좌','5년경과요건','이연퇴직소득','예외','소득세법시행령40조의2'],'cycle2_supp','cycle2_supp','소득세법 시행령 제40조의2(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 퇴직연금 항목(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=2056)','ai_draft','high','admin'),
('term','연금저축 세액공제 한도 600만 원, IRP 합산 900만 원 (2023년 상향)','2023년부터 연금계좌 세액공제 납입한도가 상향됐다. 연금저축 단독 최대 600만 원, 연금저축+IRP 합산 900만 원까지 세액공제 대상이다(소득세법 제59조의3). 세액공제율은 종합소득금액 4,500만 원(근로소득만 있으면 총급여 5,500만 원) 이하 16.5%, 초과 13.2%다. 2022년 이전 한도(400만 원/700만 원)에서 각각 200만 원씩 상향됐다.','세제',array['연금저축세액공제','IRP합산900만원','600만원한도','소득세법59조의3','2023년개정'],'cycle2_supp','cycle2_supp','소득세법 제59조의3(국가법령정보센터 law.go.kr); 국세청 연금계좌 세액공제 한도 안내(nts.go.kr/nts/cm/cntnts/cntntsView.do?cntntsId=7875)','ai_draft','high','admin'),
('term','ISA 만기자금 연금계좌 전환 시 추가 세액공제 300만 원','개인종합자산관리계좌(ISA)를 만기 또는 의무보유기간 경과 후 해지해 연금계좌(연금저축·IRP)로 이전하면, 이전 금액의 10%(최대 300만 원)를 추가 세액공제받을 수 있다(소득세법 제59조의3 제6항). ISA 만기일 또는 해지일로부터 60일 이내 이전해야 하며, 기존 연금계좌 세액공제 한도(연 900만 원) 외 추가 납입한도도 ISA 이전 금액만큼 증가한다.','세제',array['ISA만기연금전환','추가세액공제300만원','소득세법59조의3','연금계좌이전'],'cycle2_supp','cycle2_supp','소득세법 제59조의3 제6항(국가법령정보센터), 국세청 연금계좌 세액공제 한도 안내(nts.go.kr)','ai_draft','high','admin'),
('term','연금계좌 부득이한 인출 — 저율 연금소득세 적용','연금계좌에서 중도 인출 시 원칙적으로 기타소득세 16.5%가 부과되나, 소득세법에서 정한 ''부득이한 사유''(천재지변, 가입자 사망, 해외이주, 파산·개인회생 개시, 가입자 또는 부양가족 3개월 이상 요양, 특별재난지역 재난 피해 등)에 해당하면 연령별 저율 연금소득세(55~69세 5.5%, 70~79세 4.4%, 80세 이상 3.3%)가 적용된다. 사유 확인일로부터 6개월 이내 인출해야 한다. IRP의 경우 요양 요건이 더 엄격(6개월 이상, 연간 총급여의 12.5% 이상)할 수 있으므로 상품별 확인이 필요하다.','세제',array['연금계좌부득이한인출','저율과세','연금소득세','중도인출예외','기타소득세면제'],'cycle2_supp','cycle2_supp','소득세법 시행령(국가법령정보센터), 국세청 연금소득 범위 안내(nts.go.kr), 보험연구원 KIRI 리포트','ai_draft','medium','admin'),
('term','연금보험 계약자 변경과 증여세 — 연금개시 전후 과세 차이','보험료를 납입한 계약자와 수익자가 다른 경우 수익자가 연금 수령 시 증여세가 과세된다. 연금개시 전 계약자 변경 시 변경 후 계약자에게 증여세가 과세되며, 개시 후 연금 수령자가 계약자와 다를 경우 수령자에게 과세된다(상속세 및 증여세법 제34조). 증여재산가액은 미래 연금액을 현재가치로 할인한 금액과 해지환급금 중 큰 금액으로 평가한다. 계약자 변경 시 비과세 기산점은 변경일로 재산정된다(단, 사망으로 인한 변경은 최초 납입일 기준 유지).','세제',array['연금보험계약자변경','증여세','연금개시전후','수익자다른경우','상속세및증여세법'],'cycle2_supp','cycle2_supp','국세청 서면-2020-상속증여-3039(CaseNote), 상속세 및 증여세법 제34조(국가법령정보센터), 국세청 홈택스 사전-2019-법령해석재산 질의회신','ai_draft','high','admin'),
('term','연금개시 전·후 사망 시 상속재산 평가 차이','연금개시 전 사망 시 보험계약은 상속재산으로서 상속개시 당시 해지환급금 상당액으로 평가된다(상속세 및 증여세법 제8조 및 국세청 사전-2019-법령해석재산-0378). 연금개시 후 사망 시 이미 수령한 연금은 원칙상 과세 완료 소득이며, 계속 수령 예정인 연금 권리는 유기정기금 또는 종신정기금 평가방법(상속세 및 증여세법 시행령 제62조)을 적용한다. 국민연금에서 지급되는 유족연금은 상속세 과세 대상에서 제외된다.','세제',array['연금개시전사망','연금개시후사망','상속재산평가','유기정기금평가','해지환급금평가'],'cycle2_supp','cycle2_supp','상속세 및 증여세법 제8조·시행령 제62조(국가법령정보센터), 국세청 사전-2019-법령해석재산-0378','ai_draft','medium','admin'),
('term','유기정기금 평가 — 연금보험 상속·증여세 산출 기준','연금을 일정 기간 동안 수령하는 유기정기금은 상속·증여세 산출 시 매 회 수령액에 기간에 따른 할인율을 적용한 현재가치로 평가한다(상속세 및 증여세법 제65조, 시행령 제62조). 1년분 정기금액의 20배를 한도로 한다. 종신지급형 즉시연금의 경우 최저보증기간이 잔여 기대수명보다 길면 유기정기금 평가, 짧으면 종신정기금 평가 방식을 적용한다.','세제',array['유기정기금평가','상속세증여세','연금보험상속','상속세및증여세법65조','종신정기금'],'cycle2_supp','cycle2_supp','상속세 및 증여세법 제65조·시행령 제62조(국가법령정보센터), 국세청 서면-2019-상속증여-0012(CaseNote)','ai_draft','high','admin'),
('term','변액보험 특별계정 — 일반계정 분리 운용 (보험업법 제108조)','변액보험 보험료 중 저축보험료(적립보험료)는 일반계정과 분리된 특별계정에서 운용된다. 보험업법 제108조에 따라 보험회사는 변액보험계약 준비금에 상당하는 자산을 특별계정으로 설정·운용해야 하며, 특별계정 자산과 일반계정 자산은 분리 운용된다. 다만 계약자 자산 보호(파산 시 계약자 우선 귀속)는 보험업법 제108조가 아닌 보험업법 제119조 등 별도 조항에 근거하므로, 특별계정 설정이 곧 파산 완전 격리를 의미하지는 않는다.','계약',array['변액보험특별계정','일반계정분리','보험업법108조','특별계정보호','계약자적립금'],'cycle2_supp','cycle2_supp','보험업법 제108조(국가법령정보센터, LBOX 법령), CaseNote 금융위원회·금감원 일반계정·특별계정 보상책임 질의','ai_draft','medium','admin'),
('term','변액보험 최저사망보험금보증 (GMDB)','최저사망보험금보증(Guaranteed Minimum Death Benefit, GMDB)은 변액보험에서 투자 성과와 무관하게 피보험자 사망 시 최소한 기납입보험료 이상의 사망보험금을 지급하도록 보험회사가 보증하는 제도다. 보험업감독규정 제7-60조 제7호에 따라 변액보험(연금보험 제외)은 최저사망보험금 설정이 의무다. 투자 원금 손실 시에도 사망보험금은 기납입보험료 수준으로 유지된다.','보장',array['GMDB','최저사망보험금보증','변액보험최저보증','보험업감독규정7-60조','사망보험금보증'],'cycle2_supp','cycle2_supp','보험업감독규정 제7-60조 제7호(국가법령정보센터), 보험연구원 ''변액연금 최저보증 및 사업비 부과 현황 조사'' 2018(kiri.or.kr)','ai_draft','high','admin'),
('term','최저연금적립금보증 (GMAB)','최저연금적립금보증(Guaranteed Minimum Accumulation Benefit, GMAB)은 변액연금보험의 연금개시시점(제1보험기간 만기)에 계약자적립금이 기납입보험료 이하로 하락해도 약정된 최저보증금액 이상을 연금재원으로 보장하는 제도다. 2002년 국내 변액연금 판매 개시와 함께 도입됐다. 보증비용은 매월 특별계정에서 차감된다. 2016년 이후 GMAB 미보증형 상품도 허용됐으며 이 경우 연금개시 시점에 원본 손실 가능성이 있다.','보장',array['GMAB','최저연금적립금보증','변액연금보험','연금개시시점보증','원본손실가능'],'cycle2_supp','cycle2_supp','보험연구원 ''변액연금 최저보증 및 사업비 부과 현황 조사'' 2018(kiri.or.kr), KCI 학술논문 ''변액연금GMAB 미보증형 생명보험 상품의 법적용에 관한 연구''','ai_draft','high','admin'),
('term','최저종신중도인출보증 (GLWB)','최저종신인출금보증(Guaranteed Lifetime Withdrawal Benefit, GLWB)은 변액연금에서 계약자적립금이 0이 될 때까지 또는 사망 시까지 매년·매월 일정 금액을 중도 인출할 수 있도록 보험회사가 보장하는 제도다. 국내에서는 2008년 말 일부 생보사가 판매를 개시했으나 초기 실제 판매 규모는 제한적이었다. 특별계정에서 계속 투자되면서 인출이 가능하며, 사망 시 잔여 적립금이 있으면 상속인에게 환급된다. 보증비용은 특별계정에서 차감된다.','보장',array['GLWB','최저종신인출보증','변액연금','종신인출보장','2008년도입'],'cycle2_supp','cycle2_supp','보험연구원 KIRI ''변액보험 최저보증 현황조사'', 보험금융연구 제22권 제2호(2011)(kiri.or.kr)','ai_draft','medium','admin'),
('term','공시이율과 최저보증이율 — 금리연동형 보험 이율 구조','공시이율은 보험사가 운용자산이익률·외부지표금리(국고채·회사채 등 가중이동평균)를 기반으로 매월 공시하는 이율이다. 최저보증이율은 시장금리가 아무리 하락해도 보험사가 보장하는 최저 적립이율이다. 보험업감독규정 제6-12조에 따라 공시기준이율은 보장성의 경우 운용자산이익률×35% + 외부지표금리×65%, 저축·연금의 경우 운용자산이익률×30% + 외부지표금리×70%로 산출한다. 적용공시이율은 공시기준이율의 80~120% 범위 내에서 결정된다.','계약',array['공시이율','최저보증이율','금리연동형보험','보험업감독규정6-12조','공시기준이율'],'cycle2_supp','cycle2_supp','보험업감독규정 제6-12조(국가법령정보센터), DB생명 공시기준이율·공시이율 안내(idblife.com)','ai_draft','high','admin'),
('term','변액보험 펀드변경 — 연 12회 무료, 초과 시 수수료','변액보험 가입자는 특별계정 내 투자 펀드를 일반적으로 연 12회까지 무료로 변경할 수 있다. 12회 초과 변경 시 수수료가 부과되며, 구체적 기준은 보험사별 약관에 따른다. 연 12회 무료는 법령상 강제 기준이 아니라 업계 일반 관행이므로 가입 상품 약관 확인이 필요하다. 펀드변경은 투자위험을 조정하는 핵심 수단으로 보험업감독규정 및 생명보험협회 공시 기준에 따라 변액보험공시실에서 자산운용옵션(펀드변경) 현황을 공시해야 한다.','계약',array['변액보험펀드변경','연12회무료','자산운용옵션','특별계정','생명보험협회공시'],'cycle2_supp','cycle2_supp','생명보험협회 변액보험공시실(klia.or.kr) / 보험업감독규정(국가법령정보센터 law.go.kr)','ai_draft','medium','admin'),
('term','월적립식 저축성보험 비과세 요건 — 균등납입·선납 6개월 이내','월적립식 저축성보험의 보험차익 비과세 요건(소득세법 시행령 제25조): 1) 최초납입일부터 납입기간 5년 이상, 2) 계약 10년 이상 유지, 3) 매월 기본보험료 균등 납입(최초 계약 기본보험료의 1배 이내 증액 포함), 4) 기본보험료 선납기간 6개월 이내, 5) 계약자 1인당 월 보험료 합계 150만 원 이하(2017년 4월 1일 이후 계약). 선납 6개월 초과나 균등납입 위반 시 비과세 요건 미충족으로 이자소득세(15.4%) 과세된다.','세제',array['월적립식저축성보험','비과세요건','균등납입','선납6개월이내','소득세법시행령25조','150만원한도'],'cycle2_supp','cycle2_supp','소득세법 시행령 제25조 (국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','종신보험 연금전환 비과세 주의사항 — 종신형 비과세 적용 불가','종신보험을 연금전환 특약으로 전환하면 저축성보험으로 전환되어 소득세법 시행령 제25조 비과세 요건(10년 유지, 납입기간 5년 이상, 월 150만 원 이하 등)을 충족해야 비과세 혜택을 받을 수 있다. 단, 종신형 연금보험의 비과세 요건(소득세법 시행령 제25조 제1항 제1호)은 처음부터 연금 상품으로 가입한 경우에만 적용되므로, 종신보험에서 전환된 연금은 종신형 비과세 요건을 충족할 수 없다.','세제',array['종신보험연금전환','연금전환특약','비과세주의사항','종신형비과세불가','저축성보험전환'],'cycle2_supp','cycle2_supp','소득세법 시행령 제25조 (국가법령정보센터 law.go.kr)','ai_draft','medium','admin'),
('term','IRP 중도인출 원칙적 불가 — 예외 사유 (근로자퇴직급여보장법)','개인형 IRP는 원칙적으로 연금 수령 전 중도인출이 불가하다. 근로자퇴직급여보장법에서 정한 예외 사유에 해당해야 중도인출이 허용된다: 무주택자의 주택 구입·전세보증금 마련, 가입자·배우자·부양가족 6개월 이상 요양, 파산·개인회생 개시 결정(5년 이내), 자연재난·사회재난 피해, 금융기관 영업정지 등. 의료비 요건의 경우 DC형(확정기여형) 퇴직연금은 연간 임금총액의 12.5% 초과 시에만 인출 가능하나, 개인형 IRP는 해당 임금총액 기준이 적용되지 않는다.','계약',array['IRP중도인출','원칙적불가','예외사유','근로자퇴직급여보장법','DC형차이'],'cycle2_supp','cycle2_supp','근로자퇴직급여보장법 및 동법 시행령 (국가법령정보센터 law.go.kr) / 찾기쉬운 생활법령정보 — 퇴직연금 중도인출(easylaw.go.kr)','ai_draft','high','admin'),
('term','연금보험 공시기준이율 산출 구조 (운용자산이익률 + 외부지표금리)','금리연동형 연금보험의 공시기준이율은 보험업감독규정 제6-12조에 따라 운용자산이익률과 외부지표금리(국고채·회사채·CD 등 유통수익률 가중이동평균)를 특정 비율로 결합해 산출한다. 저축·연금·연금저축 계정의 표준 구성은 운용자산이익률 30% + 외부지표금리 70%이며, 실제 적용공시이율은 공시기준이율을 기준으로 조정률을 가감해 결정된다.','계약',array['공시기준이율','연금보험이율','운용자산이익률','외부지표금리','보험업감독규정6-12조'],'cycle2_supp','cycle2_supp','보험업감독규정 제6-12조 (국가법령정보센터 law.go.kr) / 보험개발원 공시기준이율 안내(bigin.kidi.or.kr)','ai_draft','high','admin'),
('term','변액보험 자산운용보고서 공시 의무','변액보험 보험회사는 보험업감독규정 및 보험업감독업무시행세칙과 생명보험협회 상품통일공시기준에 따라 특별계정 운용 현황과 자산운용보고서를 정기적으로 공시해야 한다. 계약자는 생명보험협회 변액보험공시실에서 가입 상품의 펀드별 수익률, 운용 현황, 최저보증 비용 등을 확인할 수 있다. 공시 주기(분기 또는 반기 등)는 상품 및 보험사별로 달리 운영될 수 있으므로 해당 보험사 공시실을 통해 확인하는 것이 정확하다.','계약',array['변액보험공시','자산운용보고서','특별계정운용현황','생명보험협회공시실','보험업감독규정'],'cycle2_supp','cycle2_supp','보험업감독규정 및 보험업감독업무시행세칙 (국가법령정보센터 law.go.kr) / 생명보험협회 변액보험공시실(klia.or.kr)','ai_draft','medium','admin'),
('term','퇴직소득 과세이연 — IRP 60일 이내 이전 시 소득세 이연','퇴직급여를 IRP 계좌로 직접 이전받거나, 일시금으로 수령 후 60일 이내에 IRP에 재입금하면 퇴직소득세 납부 시기가 실제 인출 시점까지 이연된다(소득세법 제22조). 과세이연 효과로 세금 미납 금액도 계속 운용되어 복리 효과를 얻을 수 있다. 60일 초과 시 퇴직소득세가 즉시 과세되어 이연 혜택을 받을 수 없다.','세제',array['퇴직소득과세이연','IRP60일이내이전','과세이연','퇴직소득세납부유예','소득세법22조'],'cycle2_supp','cycle2_supp','소득세법 제22조 (국가법령정보센터 law.go.kr) / 국세청 퇴직소득세 안내(nts.go.kr)','ai_draft','high','admin'),
('term','위법계약해지 vs 품질보증해지 vs 청약철회 3종 비교','보험계약자가 행사할 수 있는 해지·철회 권리 3종 비교. 1) 청약철회: 보험증권 수령일부터 15일 이내(청약일부터 30일 이내), 사유 불필요, 납입보험료 전액 반환(3영업일 내). 자동차보험·단기보험(90일 이내) 등 일부 제외(상법 제638조의2). 2) 품질보증해지: 약관 미교부·설명의무 위반·자필서명 누락 등 불완전판매 행위 발생 시 계약 성립일로부터 3개월 이내, 납입보험료 전액 반환(상법 제638조의3 제2항). 3) 위법계약해지: 금소법 5개 판매행위 규제 위반 시 위반 사실을 안 날부터 1년·체결일부터 5년 이내(두 기간 중 먼저 도래하는 기간까지), 서비스 제공 과정 비용 제외 후 반환. 3개월 내 불완전판매 확인 시 품질보증해지가 전액 환급으로 가장 유리.','계약',array['청약철회','품질보증해지','위법계약해지','3종비교','불완전판매','보험료반환'],'cycle2_supp','cycle2_supp','상법 제638조의2·제638조의3 (국가법령정보센터 law.go.kr) / 금융소비자 보호에 관한 법률 제47조 (law.go.kr) / 찾기쉬운 생활법령정보 — 보험계약의 철회와 취소(easylaw.go.kr)','ai_draft','high','admin'),
('term','자료열람요구권 (금소법 제28조, 6영업일 이내)','금융소비자보호법 제28조에 따라 금융소비자는 분쟁조정 또는 소송 수행 등을 위해 금융상품판매업자등에게 자신과 관련된 자료의 열람을 요구할 수 있다. 판매업자는 요구받은 날부터 6영업일(금융소비자보호법 시행령 제26조 제4항) 이내에 열람할 수 있도록 해야 한다. 다른 법령에 따라 열람이 제한되거나, 타인의 생명·재산을 해칠 우려가 있는 경우 열람 제한·거절이 가능하며, 거절·연기 시에는 사유를 서면으로 알려야 한다. 소비자는 열람 제한에 이의 시 금감원에 민원 제기 가능.','민원',array['자료열람요구권','금소법제28조','6영업일','분쟁조정','열람제한'],'cycle2_supp','cycle2_supp','금융소비자 보호에 관한 법률 제28조 및 동법 시행령 제26조 제4항 (국가법령정보센터 law.go.kr) / 찾기쉬운 생활법령정보 — 자료열람요구권(easylaw.go.kr)','ai_draft','high','admin'),
('term','소액분쟁사건 조정이탈금지 (2천만원 이하)','금융소비자보호법 제42조에 따라 손해배상청구액 등이 2천만 원 이내인 소액분쟁사건의 경우, 분쟁조정 절차가 진행 중인 동안 금융상품판매업자는 소송을 제기할 수 없다(조정이탈금지). 이와 별도로 편면적 구속력 제도는 소비자가 조정안을 수락하면 금융회사가 이를 거부할 수 없도록 하는 것으로, 2천만 원 이하 소액사건에 적용이 논의되고 있다. 조정 성립 시 재판상 화해와 동일한 효력이 발생하며, 불이행 시 강제집행 가능.','민원',array['소액분쟁조정이탈금지','2천만원','편면적구속력','금융분쟁조정','금소법 제42조'],'cycle2_supp','cycle2_supp','금융소비자보호법 제42조 (국가법령정보센터) / 보험연구원 이슈보고서 2021-22 — ''금융소비자보호법의 사후적 권익구제제도 검토''','ai_draft','high','admin'),
('term','금소법 과징금 산정 (수입등의 50% 이내, 위반 중대성별 부과기준율)','금융소비자보호법상 설명의무·불공정영업행위 금지·부당권유행위 금지·광고규제 위반 시 수입 등의 50% 이내에서 과징금을 부과할 수 있다(적합성원칙·적정성원칙 위반은 과징금 대상 아님). 구체적 산정은 위반행위의 중대성에 따라 부과기준율을 적용하며, 2025년 11월 19일 시행된 금융감독원 감독규정 개정에 따라 수입 등의 의미를 상품 유형별 거래금액으로 명확히 하고, 중대성 평가 점수에 따라 1%~100% 범위에서 세분화된 기준율을 적용한다(매우 중대 65%~100%, 중대 30%~65%, 중대성 약함 1%~30%). 과태료는 별도로 1억 원·3천만 원·1천만 원 이하 3단계로 부과된다. 과징금과 과태료는 동시 부과 가능.','민원',array['금소법과징금','수입의50%','과태료','판매원칙위반','제재','부과기준율'],'cycle2_supp','cycle2_supp','보험저널 — ''금소법 과징금 기준 확정…수입등의 최대 50% 이내'' / 금융위원회·금융감독원 감독규정 개정(2025.11.19 시행) / 대한민국 정책브리핑 — ''금소법상 6대 판매규제 중 일부 징벌적 과징금 부과대상 아니다''','ai_draft','high','admin'),
('term','금소법 손해배상 입증책임 전환 (설명의무 위반)','금융소비자보호법 제44조에 따라 금융상품판매업자등이 설명의무 등 판매행위 규제를 위반하여 소비자에게 손해를 끼친 경우, 손해배상 소송에서 ''고의 또는 과실 없음''을 판매업자가 스스로 입증해야 한다. 일반 민사소송에서는 피해자가 가해자의 과실을 입증해야 하나, 금소법에서는 이를 역전시켜 금융소비자의 입증부담을 경감하였다. 판매업자가 설명의무를 적법하게 이행했음을 증명하지 못하면 손해배상 책임을 진다.','민원',array['입증책임전환','설명의무위반','손해배상','금소법 제44조','금융소비자보호법'],'cycle2_supp','cycle2_supp','금융소비자보호법 제44조 (국가법령정보센터) / 한국소비자원 — ''금융소비자보호에 관한 법률안의 주요내용 및 시사점''','ai_draft','high','admin'),
('term','설명의무 3단계: 계약 체결·보험금 청구·심사 지급 단계','보험업감독규정 개정(금융위원회고시 제2023-10호)에 따라 보험회사의 설명의무는 3단계로 확대 적용된다. 1단계(계약 체결): 보장개시일·인수심사 과정·모집인 계약체결 권한 등 안내. 2단계(보험금 청구): 청구에 필요한 서류·심사절차·지급 예상일 등 안내. 3단계(심사·지급): 지급일·소요시간·지급기준·거절 또는 감액 사유 설명 및 동의. 각 단계별 설명사항을 이행하지 않으면 설명의무 위반으로 과태료·손해배상 책임이 발생한다.','민원',array['설명의무3단계','보험금청구단계','심사지급단계','계약체결단계','보험업감독규정'],'cycle2_supp','cycle2_supp','찾기쉬운 생활법령정보 — ''보험계약 체결 등 설명 의무사항 확대'' / 보험업감독규정 (국가법령정보센터, 금융위원회고시 제2023-10호)','ai_draft','high','admin'),
('term','미스터리쇼핑 (금융감독원 불완전판매 암행점검)','금융감독원이 외부 전문기관 조사원을 일반 고객으로 위장시켜 보험회사·GA 영업점 또는 콜센터에서 금융상품 판매 과정의 적정성을 점검하는 제도. 생명보험·손해보험·변액보험 등 주요 상품을 대상으로 적합성 원칙·설명의무·고지안내 등 5개 부문 24개 항목을 평가하며, 우수·양호·보통·미흡·저조 5등급으로 산출한다. 연간 영업점 약 1,000회·텔레마케팅 채널 약 500회(최대 총 1,500회) 실시하며, 점검 결과는 공개하고 미흡 금융사에는 개선 요구를 한다.','판매',array['미스터리쇼핑','불완전판매암행점검','금융감독원','판매원칙점검','변액보험'],'cycle2_supp','cycle2_supp','파이낸셜뉴스 — ''금감원, 내달부터 미스터리쇼핑 돌입 불완전판매 불시점검'' / 뉴스토마토 — ''금감원, 하반기 미스터리쇼핑 확대 / 점검 결과 공개한다''','ai_draft','high','admin'),
('term','적합성원칙 vs 적정성원칙 차이 (금소법)','금소법상 두 원칙의 핵심 차이: 적합성원칙(제17조)은 판매업자가 소비자에게 상품을 ''권유''하는 경우에 적용되며, 소비자의 재산·투자경험·위험감수능력 등을 파악하여 부적합한 상품을 권유하면 안 된다. 적정성원칙(제18조)은 소비자가 ''자발적으로'' 구매 의사를 보일 때 적용되며, 상품이 소비자에게 적정하지 않다고 판단되면 이를 고지해야 한다. 두 원칙 모두 위반 시 과징금 부과 대상이 아니며 과태료(1억 원 이하)만 부과된다. 보험에서는 변액보험 등 투자성 보험상품에 두 원칙 모두 적용된다.','판매',array['적합성원칙','적정성원칙','차이','변액보험','금소법 제17조','금소법 제18조'],'cycle2_supp','cycle2_supp','대한민국 정책브리핑 — ''금소법상 6대 판매규제 중 일부 징벌적 과징금 부과대상 아니다'' / 금융소비자보호법 제17조·제18조 (국가법령정보센터)','ai_draft','high','admin'),
('term','불공정영업행위 금지 — 구속성 판매(꺾기) 포함 (금소법 제20조)','금소법 제20조에 따라 금융상품판매업자등은 우월적 지위를 이용하여 소비자 권익을 침해하는 불공정영업행위를 해서는 안 된다. 대표적 유형: 1) 구속성 판매(꺾기): 대출 실행 조건으로 보험·펀드 등 다른 금융상품 가입 강요. 2) 유지·해지 방해: 수익자 변경·해지를 부당하게 제한. 3) 부당 정보 수집: 금융거래 관계 없는 개인정보 요구. 위반 시 과징금(수입의 50% 이내) 또는 과태료(1억 원 이하) 부과 대상.','판매',array['불공정영업행위','꺾기','구속성판매','우월적지위남용','금소법 제20조'],'cycle2_supp','cycle2_supp','금융소비자보호법 제20조 (국가법령정보센터) / 퍼블릭뉴스 — ''꺾기 행위 의심되면 금융상품 가입 거절할 수 있다'' / 다자비 보험AI뉴스 — ''금소법 과징금 세분화 11월19일 시행''','ai_draft','high','admin'),
('term','부당권유행위 금지 유형 (금소법 제21조)','금소법 제21조에 따라 금융상품판매업자등은 다음 부당권유행위를 할 수 없다. 1) 불확실 사항에 대한 단정적 판단 제공(예: ''무조건 오릅니다''). 2) 금융상품 내용을 사실과 다르게 알리는 행위(허위고지). 3) 소비자가 요청하지 않았는데 방문·전화로 계약 체결을 권유하는 행위. 4) 소비자가 거부 의사를 밝혔음에도 계속 권유. 5) 보험 분야: 피보험자가 보험사에 중요사항을 고지하는 것을 방해하거나 부실고지를 권유하는 행위. 위반 시 과태료 또는 과징금 부과(부당권유는 6대 판매규제 중 과징금 부과 가능 항목에 포함).','판매',array['부당권유행위','단정적판단금지','허위고지','고지방해','금소법 제21조'],'cycle2_supp','cycle2_supp','금융소비자보호법 제21조 (국가법령정보센터) / 아주경제 — ''금소법 이것만은 꼭: 불공정 영업·부당권유에 해당하는 경우'' / 다자비 보험AI뉴스 — ''금소법 과징금 세분화 11월19일 시행''','ai_draft','high','admin'),
('term','금소법 광고규제 — 보험 상품광고 필수 기재 항목','금소법 제22조에 따라 금융상품판매업자등이 보험상품을 광고하는 경우 필수 안내사항을 포함해야 한다. 주요 항목: 상품설명서·약관 열람 권유, 기존 계약 해지 후 재가입 시 보험료 인상·보장 변경 가능성 안내, 해약환급금이 납입보험료보다 적을 수 있다는 안내, 글자 색깔·크기·음성 속도 등이 혜택과 불이익을 균형 있게 전달하도록 구성 등. GA나 설계사도 상품광고를 하려면 소속 보험사의 협회 광고 심의를 거쳐야 한다. 필수 기재 항목의 정확한 수(원 body ''20개'')는 금융위원회 금융광고규제 가이드라인 및 금융상품 표시·광고 심사지침에서 상품 유형별로 달리 규정하므로, 단일 ''20개''로 단정하기보다 관련 감독규정 기준에 따른다.','판매',array['광고규제','보험광고필수항목','금소법 제22조','광고심의','GA광고'],'cycle2_supp','cycle2_supp','금융위원회 — ''금융광고규제 가이드라인'' / 보험연구원 주간동향 2025.03.10 — ''GA 및 설계사의 상품광고'' / 국가법령정보센터 — ''금융상품 등의 표시·광고에 관한 심사지침''','ai_draft','medium','admin'),
('term','금융소비자보호 실태평가 (금융감독원, 8개 항목 5등급)','금융감독원은 금융소비자보호법에 근거하여 보험회사를 포함한 금융회사의 소비자보호 수준을 종합 평가하는 ''금융소비자보호 실태평가''를 실시한다. 평가항목은 계량(2개: 민원건수·증감률 포함) + 비계량(6개: 소비자보호 조직·제도, 상품개발 시 소비자보호, 판매과정 보호 등) 총 8개 항목. 평가등급은 우수·양호·보통·미흡·취약 5단계. 금소법 시행(2021년) 이후 평가대상 금융회사를 3개 그룹으로 나누어 매년 1개 그룹씩 평가하므로 개별 회사 기준 3년 주기가 된다(비공식 연도 자율진단 방식 병행). 결과는 각 보험사 홈페이지 및 손해보험협회·생명보험협회에 공시.','민원',array['금융소비자보호실태평가','금융감독원','5등급','민원건수','소비자보호공시'],'cycle2_supp','cycle2_supp','금융감독원 금융소비자보호처 / 손해보험협회 소비자보호 공시 (consumer.knia.or.kr) / 보험연구원 주간동향 2024.12.23 — ''24년 금융소비자보호 실태평가 결과''','ai_draft','medium','admin'),
('term','민원발생평가 등급 공시 (금융감독원, 1~5등급)','금융감독원은 보험회사 등 금융회사의 민원 발생 건수, 처리결과, 영업규모를 종합 고려하여 1등급(우수)부터 5등급(매우미흡)까지 5단계 등급을 부여하고 이를 공시한다. 생명보험협회·손해보험협회 및 각 보험사 홈페이지에 공시된다. 영업규모(고객 수 등)와 민원 건수 비중이 업권 내 1% 이하인 소형사는 등급 미산정. 민원발생평가 등급은 보험사 선택 시 소비자 참고지표로 활용되며, 불이행 시 감독·검사상 불이익이 따른다.','민원',array['민원발생평가등급','금융감독원공시','보험민원','1~5등급','생손보협회'],'cycle2_supp','cycle2_supp','손해보험협회 공시 시스템 (kpub.knia.or.kr) — 민원발생평가등급 공시 / 금융감독원 FINE (fine.fss.or.kr)','ai_draft','high','admin'),
('term','고령금융소비자 보호 — 만 65세 이상 숙려제도·보호기준','금융소비자보호법 및 관련 감독규정에 따라 만 65세 이상은 고령금융소비자로 분류되어 강화된 보호를 받는다. 보험 판매 시 1) 충분한 설명과 이해 확인, 2) 가족 등 조력자 동석 권유, 3) 숙려기간 부여, 4) 전화·녹취 등 별도 확인 절차 적용 등을 준수해야 한다. 고난도 금융상품(파생결합증권 등) 분야에서는 고령 기준이 70세에서 65세로 조정된 바 있다(금소법 시행령 개정). 인지능력이 현저히 저하된 65세 미만도 준용 가능하다. 보험 전반에 대한 1~2일 숙려기간 의무화는 금융감독원 가이드라인 수준으로, 법령 명문 규정과는 구분이 필요하다.','판매',array['고령금융소비자','65세이상','숙려제도','보호가이드라인','고령자보험판매'],'cycle2_supp','cycle2_supp','금융소비자보호법 시행령(국가법령정보센터) / 금융위원회 보도자료 — 고난도상품 고령기준 70세→65세 조정 / 금융감독원 금융소비자보호처','ai_draft','medium','admin'),
('term','금융소비자보호 내부통제기준 및 CCO 의무 (금소법 제32조)','금소법 제32조에 따라 보험회사를 포함한 금융상품판매업자등은 금융소비자보호 내부통제기준을 의무적으로 마련해야 한다. 내부통제기준에는 소비자보호 업무 절차, 임직원 교육, 민원처리 체계 등이 포함된다. 금융소비자보호 총괄책임자(CCO)를 지정해야 하며, CCO는 판매행위 준수 여부를 주기적으로 점검하고 대표이사에게 보고한다. 단, 내부통제위원회의 구성 요건(대표이사·CCO·사내임원 등)은 금소법 제32조가 아닌 ''금융회사의 지배구조에 관한 법률'' 등 별도 법령에서 규율하므로 혼용에 주의해야 한다.','판매',array['내부통제기준','CCO','금융소비자보호총괄책임자','보험회사의무','금소법 제32조'],'cycle2_supp','cycle2_supp','금융소비자보호법 제32조(국가법령정보센터) / 금융소비자 보호에 관한 감독규정 제9조 [별표2](국가법령정보센터) / 금융회사의 지배구조에 관한 법률(국가법령정보센터)','ai_draft','medium','admin'),
('term','전문금융소비자 vs 일반금융소비자 구분 및 전환 요건','금소법상 금융소비자는 전문금융소비자(국가·지방자치단체·금융회사·주권상장법인 등)와 일반금융소비자(그 외)로 구분된다. 적합성원칙·적정성원칙·설명의무 등 판매규제의 보호 강도가 다르며, 일반금융소비자에게 더 강한 보호가 적용된다. 전문금융소비자 중 대통령령으로 정하는 자가 일반금융소비자와 같은 대우를 받겠다는 의사를 서면으로 통지하면, 금융상품판매업자등은 정당한 사유가 없는 한 이에 동의해야 하며 동의한 경우 해당 소비자는 일반금융소비자로 간주된다. 반대로 일반금융소비자가 전문금융소비자와 동일한 방식으로 대우받겠다는 서면 동의를 한 경우 해당 거래에서 전문소비자 취급이 가능하다.','판매',array['전문금융소비자','일반금융소비자','구분','전환요건','판매규제적용범위'],'cycle2_supp','cycle2_supp','금융소비자보호법 제2조(국가법령정보센터) / 찾기쉬운 생활법령정보 — ''금융상품 및 금융소비자 알아보기''','ai_draft','high','admin'),
('term','금융상품 직접판매업자의 손해배상책임 (금소법 제45조)','금소법 제45조에 따라 금융상품직접판매업자는 금융상품판매대리·중개업자(보험 GA·설계사 포함)가 업무수행 중 금융소비자에게 손해를 입힌 경우 해당 손해를 배상해야 한다. 이를 통해 보험회사의 GA에 대한 관리감독 책임이 명확해졌다. 보험회사는 1차 배상 후 GA 등 판매대리·중개업자에게 구상권을 행사할 수 있다. 다만, ''구 보험업법 제102조 조항이 금소법 제45조로 이관됐다''는 서술은 정확하지 않으며, 보험업법 제102조는 금소법 시행 이후에도 별도로 존재한다.','판매',array['손해배상책임','금소법 제45조','보험회사책임','GA책임','구상권'],'cycle2_supp','cycle2_supp','금융소비자보호법 제45조(국가법령정보센터) / 보험업법 제102조(국가법령정보센터)','ai_draft','medium','admin'),
('term','보험약관 설명의무 위반 취소권 (계약 성립일로부터 1개월, 상법 제638조의3)','상법 제638조의3 제2항에 따라 보험자가 약관 교부 및 중요 내용 설명의무를 위반한 경우, 보험계약자는 계약 성립일로부터 1개월 이내에 보험계약을 취소할 수 있다. 이 취소권은 권리이지 의무가 아니며, 취소권을 행사하지 않더라도 보험자의 설명의무 위반의 법률효과가 소멸하거나 하자가 치유되는 것은 아니다. 본 취소권은 금소법상 청약철회권(15일/30일) 및 품질보증해지(3개월)와 별도로 존재하며, 취소 시 납입한 보험료 전액 반환이 원칙이다.','계약',array['약관설명의무위반취소권','1개월취소권','상법 제638조의3','약관교부의무위반','보험계약취소'],'cycle2_supp','cycle2_supp','상법 제638조의3(국가법령정보센터) / 대법원 판례(국가법령정보센터) / 찾기쉬운 생활법령정보 — ''보험계약의 철회와 취소''','ai_draft','high','admin'),
('term','독립금융상품자문업 (금소법상 IFA — 보험 포함 전 금융상품 자문)','금소법 제정으로 도입된 독립금융상품자문업자(IFA)는 특정 금융회사에 소속되지 않고 보험·대출·예금·투자상품 등 모든 유형의 금융상품에 대해 독립적으로 자문을 제공할 수 있다. 기존 자본시장법상 독립투자자문업자(투자성 상품 한정)를 확대한 것으로, 보험 자문도 포함된다. 보수는 금융소비자로부터 직접 자문수수료를 받으며, 금융회사로부터 판매 수수료를 받을 수 없어 이해충돌 방지 구조를 갖는다.','판매',array['독립금융상품자문업','IFA','보험자문','금소법','자문수수료','이해충돌방지'],'cycle2_supp','cycle2_supp','금융소비자보호법(국가법령정보센터) / 보험연구원(KIRI) — ''금융소비자보호법상 금융상품자문업자 제도의 개요와 전망''','ai_draft','high','admin'),
('term','분쟁조정 재판상화해 효력 및 강제집행 (금소법·금융위원회설치법)','금융분쟁조정위원회의 조정안을 양 당사자가 수락하면 해당 조정조서는 재판상 화해와 동일한 효력이 발생한다(확정판결과 같은 효력). 금융회사가 조정 내용을 이행하지 않을 경우 별도 소송절차 없이 조정서를 근거로 강제집행이 가능하다. 분쟁조정 신청은 소멸시효를 중단시키는 효력이 있다. 단, 합의권고를 하지 않거나 조정위원회에 회부하지 않은 때에는 시효중단 효력이 없다. 조정결정 통보 후 20일 이내에 양 당사자가 수락서를 제출해야 조정이 성립된다.','민원',array['분쟁조정재판상화해','강제집행','확정판결동일효력','금융분쟁조정위원회','소멸시효중단'],'cycle2_supp','cycle2_supp','금융감독원 금융소비자보호처 — ''분쟁조정의 효력''(fss.or.kr) / 찾기쉬운 생활법령정보 — ''금융분쟁조정위원회의 분쟁조정''','ai_draft','high','admin'),
('term','금융소비자보호 실태평가 vs 민원발생평가 차이','보험사에 대한 금융당국의 소비자보호 관련 평가는 두 가지로 구분된다. 1) 금융소비자보호 실태평가: 금소법 제32조 근거, 평가대상 회사를 3개 그룹으로 나눠 매년 1개 그룹씩 평가하는 방식으로 3년 주기 순환, 계량·비계량 항목 종합 평가(내부통제·판매과정·민원처리 체계 등), 5등급 체계. 2) 민원발생평가: 금융감독원이 금융회사별 민원발생 건수·처리결과·회사 규모 등 계량지표 위주로 평가, 분기 공시. 두 평가 모두 결과 공시 의무가 있으며, 소비자는 보험사 선택 시 두 지표를 모두 참고할 수 있다.','민원',array['금융소비자보호실태평가','민원발생평가','차이','보험회사평가','5등급'],'cycle2_supp','cycle2_supp','손해보험협회 금융소비자보호 실태평가 공시(kpub.knia.or.kr) / 금융감독원 금융소비자보호처 실태평가 안내 / 금소법 제32조(국가법령정보센터)','ai_draft','medium','admin'),
('term','청약철회권 납입보험료 반환 기한 (3영업일)','금소법 제46조 및 표준약관에 따라 보험계약자가 청약 철회를 접수하면 보험회사는 3일(영업일 기준) 이내에 납입된 보험료 전액을 반환해야 한다. 3일 이내 반환하지 않으면 해당 보험계약의 보험계약대출 이율을 연단위 복리로 계산한 지연이자를 추가 지급해야 한다. 청약철회권 적용 제외 상품으로는 자동차보험, 보험기간 90일 이내 단기보험, 질병·상해보험 중 이미 보험금 지급 사유가 발생한 경우 등이 있다.','계약',array['청약철회','3영업일반환','지연이자','적용제외상품','금소법 제46조'],'cycle2_supp','cycle2_supp','금소법 제46조(국가법령정보센터) / 찾기쉬운 생활법령정보 — ''계약의 청약철회권'' / 보험계약자 표준약관','ai_draft','high','admin'),
('term','금소법 과태료 3단계 체계 (1억·3천만·1천만원 이하)','금소법 제69조에 따라 과태료는 위반행위 유형별로 3단계로 부과된다. 1억 원 이하: 설명의무 미이행·확인서 미수취 등 주요 판매행위 위반. 3천만 원 이하: 자료·정보 제공 의무 위반 등. 1천만 원 이하: 계약서류 미제공, 광고규제 위반 등 경미한 위반. 개인(설계사)과 법인(보험회사·GA) 모두 동일 조항이 적용되나 실제 부과 금액은 감경 규정에 따라 달라질 수 있다. 과태료는 과징금과 달리 행정질서법 위반 제재이며, 경우에 따라 중복 부과 가능하다.','민원',array['과태료','1억이하','3천만원이하','1천만원이하','금소법 제69조','판매원칙위반제재'],'cycle2_supp','cycle2_supp','금융소비자보호법 제69조(국가법령정보센터)','ai_draft','medium','admin'),
('term','보험 금융소비자 권리구제 4대 채널','보험계약 관련 피해 발생 시 소비자가 활용할 수 있는 권리구제 채널 4가지. 1) 보험회사 민원부서 직접 접수(1차). 2) 금융감독원 금융소비자보호처(1332 콜센터, 파인 홈페이지, 방문·우편): 민원 접수 후 30일 내 합의 권고, 불성립 시 조정위원회에 회부, 60일 이내 조정안 작성. 3) 한국소비자원·소비자분쟁조정위원회. 4) 법원 소송(조정 불성립 또는 소액 한도 초과 사건). 금감원 분쟁조정 신청은 소멸시효를 중단시키는 효력이 있다.','민원',array['권리구제채널','금융감독원1332','분쟁조정신청','소비자원','소송'],'cycle2_supp','cycle2_supp','찾기쉬운 생활법령정보 — ''금융분쟁조정위원회의 분쟁조정'' / 금융감독원 FINE(fine.fss.or.kr)','ai_draft','high','admin'),
('term','보험 GA·보험회사 행정제재 유형 (영업정지·등록취소·과태료)','보험업법 위반 시 금융감독원이 부과하는 행정제재 유형: 1) 등록취소: 등록제한사유에 해당하게 된 경우, 업무정지 처분을 2회 이상 받은 경우 등. 2) 영업정지(업무정지): 모집에 관한 보험업법 규정 위반 시 6개월 이내 업무정지. 3) 과태료: 보험업법 제209조에 따라 건당 최대 수천만 원. 4) 과징금: 보험업법상 특별이익 제공(제98조) 위반은 해당 보험계약의 연간 수입보험료 이하의 과징금이 부과되며, 금소법 위반이 병합되는 경우 별도 과징금이 추가될 수 있다. 특별이익 제공(보험료 대납·금품 제공 등)은 가장 빈번하게 등록취소·영업정지 처분이 내려지는 유형이다.','판매',array['행정제재','등록취소','영업정지','특별이익제공금지','보험업법 제98조','GA제재'],'cycle2_supp','cycle2_supp','보험업법 제98조·제209조(국가법령정보센터) / 찾기쉬운 생활법령정보 — ''보험설계사에 대한 제재''','ai_draft','medium','admin'),
('term','금융분쟁조정위원회 구성 및 처리 절차 (60일 조정안 작성)','금융감독원 내에 설치된 금융분쟁조정위원회는 금융소비자와 금융회사 간 분쟁을 심의·의결한다. 절차: 1) 금감원에 분쟁조정 신청. 2) 신청 접수 후 30일 이내 합의 권고. 3) 합의 불성립 시 금융분쟁조정위원회에 회부. 4) 위원회는 회부받은 날부터 60일 이내 조정안 작성. 5) 양 당사자가 조정안을 20일 이내 수락하면 재판상 화해 효력 발생. 소액분쟁(2천만 원 이하)은 금융회사의 소송 제기가 제한된다(조정이탈금지).','민원',array['금융분쟁조정위원회','60일조정안','30일합의권고','재판상화해','소액조정이탈금지'],'cycle2_supp','cycle2_supp','금융소비자 보호에 관한 법률 제36조·제42조 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 — ''금융분쟁조정위원회의 분쟁조정'' (easylaw.go.kr)','ai_draft','high','admin'),
('term','부당 승환계약 6개월 규정','기존 보험계약이 소멸된 날부터 6개월 이내에 새로운 보험계약을 청약하게 하거나, 새로운 보험계약을 청약하게 한 날부터 6개월 이내에 기존 계약을 소멸시키면서 중요 사항(보험기간·예정이자율 등)을 비교 설명하지 않은 경우 부당 승환계약으로 간주한다. 보험업법 제97조 및 보험업감독규정에 명시된 기준이며, 위반 시 설계사 업무정지·등록취소 및 형사처벌 대상이 될 수 있다.','판매',array['부당승환6개월','승환계약규정','기존계약소멸','비교설명의무','보험업감독규정'],'cycle2_supp','cycle2_supp','보험업법 제97조 / 보험업감독규정 (금융위원회고시 제2026-1호, law.go.kr)','ai_draft','high','admin'),
('term','보험사기방지 특별법상 조사권한 및 자료제출 요청','보험사기방지 특별법(2016년 제정, 2024년 8월 14일 개정)은 금융감독원장이 보험사기 혐의 조사를 위해 보험회사·요양기관·수사기관 등에 자료 제출을 요청할 수 있는 권한을 부여한다. 보험업법 제163조에 설치된 보험조사협의회를 통해 금융위원회·금감원·경찰청·보건복지부·건강보험심사평가원 등 관계기관 합동 조사 및 협조 체계를 구축하며, 보험사기 적발 시 검찰·경찰에 혐의사실을 통보한다. 2023년 기준 보험사기 누수 추정액은 약 8조 1,833억 원이다(보험연구원 연구보고서 2023-11).','민원',array['보험사기방지특별법','조사권한','자료제출요청','보험조사협의회','금감원'],'cycle2_supp','cycle2_supp','보험사기방지 특별법 (국가법령정보센터, 2024.08.14. 시행본) / 보험업법 제163조 / 보험연구원 연구보고서 2023-11 (kiri.or.kr)','ai_draft','medium','admin'),
('term','입원적정성 심사 (보험사기방지 특별법)','보험사기방지 특별법 제7조에 근거해 수사기관이 보험사기 행위 수사를 위해 입원의 의학적 필요성·적정성 심사가 필요하다고 판단할 경우 건강보험심사평가원에 심사를 의뢰할 수 있다. 장기 입원, 반복 입원, 의료기관 집중 클러스터 등 보험사기 패턴으로 의심되는 건을 선별하며, 심사 결과는 수사기관에 통보되어 보험금 지급 여부 또는 수사기관 통보 여부 결정에 활용된다.','민원',array['입원적정성심사','보험사기방지특별법제7조','건강보험심사평가원','수사기관의뢰','보험사기적발'],'cycle2_supp','cycle2_supp','보험사기방지 특별법 제7조 (국가법령정보센터, law.go.kr) / 금감원 보험사기방지센터 (fss.or.kr)','ai_draft','medium','admin'),
('term','GA 불완전판매비율 공시 의무','법인보험대리점(GA)은 보험업법 제87조의3 및 동법 시행령 제33조의4에 따라 반기별로 불완전판매비율, 보험금 부지급률, 민원발생평가등급 등을 공시해야 한다. 공시는 손해보험협회(kpub.knia.or.kr) 법인대리점공시 화면에서 확인할 수 있다. 불완전판매 유형 중 상품설명의무 위반이 가장 큰 비중을 차지하며, 지속적으로 개선 추세에 있다.','판매',array['GA불완전판매비율공시','법인대리점공시','보험업법제87조의3','반기공시','민원발생평가'],'cycle2_supp','cycle2_supp','보험업법 제87조의3 / 보험업법 시행령 제33조의4 (국가법령정보센터, law.go.kr) / 손해보험협회 법인대리점 공시 (kpub.knia.or.kr)','ai_draft','high','admin'),
('term','GA 준법감시인 의무 설치 (대형 GA 요건)','소속 보험설계사가 500인 이상인 대형 법인보험대리점(GA)은 보험업감독규정에 따라 내부통제기준 마련 의무가 있으며, 1,000인 이상 초대형 GA는 준법감시인 지원조직 설치가 의무화된다. 준법감시인은 최소 2년 임기 보장 및 보험회사 수준의 자격 요건이 적용되고, 모집 등 영업활동 겸직이 금지된다. 3단계 내부통제 자율점검(영업조직→준법감시인→이사회)이 매년 1회 이상 요구된다.','판매',array['GA준법감시인','대형GA내부통제','소속설계사500인','보험업감독규정별표9','GA감독강화'],'cycle2_supp','cycle2_supp','보험업감독규정 별표9 (금융위원회고시 제2026-1호, law.go.kr) / 보험연구원 이슈보고서 (kiri.or.kr)','ai_draft','high','admin'),
('term','보험설계사 유지(보수)교육 이수 의무','보험설계사는 최초 등록일로부터 매 2년마다(2년이 된 날부터 6개월 이내) 보수교육을 이수해야 한다(보험업법 시행령 제29조의2 제1항, 별표 4). 불완전판매 계약 비율이 1% 이상이고 건수가 3건 이상인 설계사는 추가로 불완전판매 방지 교육을 해당 사업연도에 이수해야 하며(보험업감독규정 제4-5조), 교차모집 설계사는 5시간 이상 추가 이수가 필요하다.','판매',array['보험설계사보수교육','유지교육의무','2년주기교육','불완전판매방지교육','보험업법시행령별표4'],'cycle2_supp','cycle2_supp','보험업법 시행령 제29조의2 별표4 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 보험모집인 편 교육이수의무 (easylaw.go.kr)','ai_draft','high','admin'),
('term','모집종사자 등록 결격사유','보험업법 제84조·제86조에 따라 피성년후견인·피한정후견인, 파산선고를 받고 복권되지 않은 자, 금고 이상의 실형 선고 후 집행 종료·면제 후 2년 미경과자, 보험업법 위반으로 등록취소된 날부터 2년 미경과자, 보험대리점 등록취소 처분을 2회 이상 받고 최종 취소일부터 3년 미경과자 등은 보험설계사·보험대리점으로 등록할 수 없다. 협회는 MISI 시스템을 통해 결격 여부를 확인한다.','판매',array['모집종사자결격사유','보험설계사등록자격','보험업법제84조','등록취소결격','피성년후견인'],'cycle2_supp','cycle2_supp','보험업법 제84조·제86조 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 보험설계사 등록 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','보험회사의 모집관련 손해배상책임 (보험업법 제102조)','보험업법 제102조는 보험회사가 임원·직원·보험설계사·보험대리점이 모집 과정에서 보험계약자에게 가한 손해를 배상할 책임을 규정한다. 임직원 행위에 대해서는 무과실책임에 가깝고, 설계사·대리점의 불법 모집행위에 대해서는 보험회사가 선임·감독상 과실을 입증하지 못하면 책임을 진다. 설계사 개인도 민법 제750조에 따라 별도 불법행위 책임을 진다.','민원',array['보험업법제102조','모집배상책임','보험회사배상책임','설계사불법행위','무과실책임'],'cycle2_supp','cycle2_supp','보험업법 제102조 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 보험모집인 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','보험업법 제98조 특별이익 제공 금지 및 보험료 대납 금지','보험업법 제98조는 모집종사자가 보험계약 체결 유인을 위해 보험계약자·피보험자에게 특별이익(리베이트·금품·경품 등)을 제공하거나 보험료를 대납하는 행위를 금지한다. 위반 시 3년 이하 징역 또는 3,000만 원 이하 벌금(보험업법 제202조)이 부과되며, 해당 보험계약 연간 수입보험료 이하의 과징금도 별도 부과된다. 특별이익을 요구하거나 받은 계약자도 동일한 제재 대상이다.','판매',array['특별이익제공금지','보험료대납금지','보험업법제98조','리베이트금지','과징금'],'cycle2_supp','cycle2_supp','보험업법 제98조·제202조 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 특별이익제공금지 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','자기계약 금지 원칙 (보험대리점·보험설계사)','보험업법 제101조는 보험대리점이 자기 또는 자기 고용인을 보험계약자·피보험자로 하는 보험을 ''주된 목적''으로 모집하는 것을 금지한다. 자기계약 보험료 누계가 모집 전체 보험료의 50%를 초과하면 주된 목적으로 간주된다. 위반 시 6개월 이내 업무정지 또는 등록취소 처분을 받을 수 있다. 설계사 개인에게도 유사한 준수 의무가 적용된다.','판매',array['자기계약금지','보험업법제101조','본인계약금지','50%초과기준','등록취소'],'cycle2_supp','cycle2_supp','보험업법 제101조 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 보험대리점 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','통신수단 모집 준수사항 및 녹취 의무 (보험업법 제96조)','보험업법 제96조 및 동법 시행령 제43조에 따라 전화(TM) 모집 시 보험계약자의 동의를 받아 청약 내용·보험료·보험기간·고지의무·약관 주요사항을 설명하고 답변 및 확인 내용을 음성녹음하여 증거자료로 확보·유지해야 한다. 청약 철회, 계약 내용 확인 시에도 동일하게 녹취가 의무화된다. 녹취 미비 시 계약 자체의 효력이 다툼의 대상이 될 수 있다.','판매',array['통신수단모집','TM녹취의무','전화모집준수사항','보험업법제96조','음성녹음증거'],'cycle2_supp','cycle2_supp','보험업법 시행령 제43조 제2항 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 통신매체 계약체결 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','절판마케팅 금지 (보험업법 제97조 적용)','보험업법 제97조 금지행위에 따라 보험 상품의 판매 종료나 보험료 인상이 확정되지 않았음에도 ''곧 없어진다'', ''마지막 기회다'' 등의 허위·과장 정보를 제공해 청약을 유도하는 절판마케팅은 금지된다. 불확실한 사항에 대한 단정적 판단 제공 또는 오인하게 할 소지가 있는 내용을 알리는 행위에 해당하며, 2,000만 원 이하 과태료 처분 대상이 된다.','판매',array['절판마케팅금지','보험업법제97조','허위사실금지','단정적판단금지','모집금지행위'],'cycle2_supp','cycle2_supp','보험업법 제97조 및 제209조 제4항 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 보험설계사 준수사항 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','MISI (모집종사자 정보시스템)','손해보험협회가 운영하는 보험모집종사자 정보통합시스템(MISI, misi.knia.or.kr)으로, 보험설계사의 등록·말소·이력 조회, 자격시험 신청·합격 확인, 해촉증명서에 의한 말소 신청 등의 기능을 제공한다. 생명보험협회도 별도 설계사 등록시스템을 운영하며, 양 협회는 금융위원회·금감원과 정보 공유 체계를 갖추고 있다. 보험업법 제84조에 따른 등록 의무의 실무 인프라다.','판매',array['MISI','모집종사자정보시스템','설계사등록조회','손해보험협회','모집정보관리'],'cycle2_supp','cycle2_supp','손해보험협회 모집종사자 포털 (misi.knia.or.kr) / 보험업법 제84조 (law.go.kr)','ai_draft','medium','admin'),
('term','보험설계사 제재 (업무정지·등록취소) 처분 기준','보험업법 제85조에 따라 금융위원회는 보험설계사가 모집 관련 보험업법 규정 위반, 명령·처분 위반, 과태료 처분 2회 이상 수령, 금소법 제51조 각 호 해당 시 6개월 이내 업무정지 또는 등록취소를 명할 수 있다. 처분 전 반드시 청문 절차를 거쳐야 하며, 처분 내용은 해당 설계사 및 소속 보험회사·대리점·중개사에 문서로 통지된다.','판매',array['보험설계사제재','업무정지처분','등록취소처분','보험업법제85조','청문절차'],'cycle2_supp','cycle2_supp','보험업법 제85조 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 보험설계사 제재 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','작성계약 (가공계약)','실제 보험 가입 의사가 없는 계약자(지인·가족 등)를 동원하거나 허위 정보로 보험계약을 체결한 후 수수료를 수령하고 단기에 해지하는 행위다. 보험업법 제97조 및 사기죄(형법)에 해당하며, 보험사기방지 특별법 적용 대상이기도 하다. 발각 시 설계사 등록취소, 형사처벌, 수수료 전액 환수 조치가 가해진다.','판매',array['작성계약','가공계약','허위계약','보험사기방지특별법','수수료편취'],'cycle2_supp','cycle2_supp','보험업법 제97조 (국가법령정보센터, law.go.kr) / 보험사기방지 특별법 (law.go.kr)','ai_draft','high','admin'),
('term','온라인 보험 모집 자필서명·전자서명 요건','보험업법 시행령 제43조에 따라 사이버몰(인터넷) 모집 시 보험계약자는 전자서명법 제2조 제2호에 따른 전자서명(서명자 실지명의 확인 가능한 것) 또는 금융위원회가 정하는 안전·신뢰성 기준을 충족하는 수단으로 청약 내용을 확인해야 한다. 해당 요건을 충족한 경우 자필서명을 대체할 수 있다. 요건 미비 계약은 계약 효력 다툼의 원인이 된다.','계약',array['온라인보험모집','전자서명요건','사이버몰모집','자필서명면제','보험업법시행령제43조'],'cycle2_supp','cycle2_supp','보험업법 시행령 제43조 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 통신매체 계약체결 편 (easylaw.go.kr)','ai_draft','medium','admin'),
('term','보험모집 시 금지행위 체계 (보험업법 제97조)','보험업법 제97조는 보험계약 체결·모집 종사자의 금지행위를 열거한다. 주요 금지사항: 사실과 다른 내용 고지, 불명확한 비교 광고, 기존 계약 부당 소멸 유도(부당 승환), 단정적 판단 제공, 고지의무 불고지 유도, 중요 사항 누락 등. 위반 시 2,000만 원 이하 과태료 및 등록취소·업무정지 행정처분이 가능하며, 중대 위반은 형사처벌 대상이다.','판매',array['보험업법제97조','모집금지행위열거','부당모집행위','고지의무불고지유도금지','과태료2000만원'],'cycle2_supp','cycle2_supp','보험업법 제97조 및 제209조 제4항 (국가법령정보센터, law.go.kr) / 찾기쉬운 생활법령정보 보험설계사 준수사항 편 (easylaw.go.kr)','ai_draft','high','admin'),
('term','보험설계사 신규 등록 교육 및 자격시험 요건','보험설계사가 되려면 보험업법 제84조·시행령 별표4에 따라 보험연수원 등 금융위원회 지정 기관이 실시하는 생명보험·손해보험·제3보험 관련 연수과정을 이수하고 보험협회 자격시험에 합격해야 한다. 생명·손해·제3보험 관계 업무 1년 이상 종사 경력자(등록신청일로부터 3년 이내)는 교육 이수만으로 등록 가능하다(시험 면제). 등록은 소속 보험회사 또는 GA를 통해 생명보험협회 또는 손해보험협회에 신청한다.','판매',array['보험설계사신규등록','보험연수원교육','설계사자격시험','보험업법제84조','MISI등록절차'],'cycle2_supp','cycle2_supp','찾기쉬운 생활법령정보 보험설계사 개념 및 등록 편 (easylaw.go.kr) / 보험업법 제84조 및 시행령 별표4 (law.go.kr)','ai_draft','high','admin'),
('term','GA 판매책임 강화 입법 논의 (소속설계사 1차 책임)','보험연구원 연구보고서 및 국회 발의 법안에 따르면, 소속설계사 500인 이상 대형 GA와 그 설계사의 불완전판매·모집 위법행위에 대해 GA가 1차 배상책임을 부담하고, GA가 해산·무자력 등으로 이행 불가 시 보험회사가 보충 책임을 지는 구조의 입법이 논의되고 있다. 현행법상 보험회사가 직접 책임을 지는 구조에서 GA의 독립 책임을 강화하는 방향이다. 다만 ''보험판매전문회사'' 전환 논의와 맞물려 있으며, 수수료 개편 지연 등으로 입법 진행이 불투명한 상태다.','판매',array['GA판매책임강화','대형GA1차책임','보험회사보충책임','제판분리','입법논의'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 ''보험판매채널이 소비자를 최우선할...'' (fsc.go.kr) / 보험연구원 CEO Report 보험개혁회의 내용과 과제 (kiri.or.kr, 2025.09) / 한국금융연구원 금융브리프 (kcif.re.kr)','ai_draft','medium','admin'),
('term','방카슈랑스 수수료 공시','보험업법 및 보험업감독규정에 따라 은행 등 금융기관보험대리점(방카슈랑스 채널)은 보험상품 판매 수수료율을 공시해야 한다. 손해보험협회는 방카슈랑스 모집수수료율 공시 화면(kpub.knia.or.kr)을 운영하며, 금융기관보험대리점의 수수료 투명성 제고를 위해 금융위원회 감독 하에 관리된다. 보험업감독규정 제4-16조(금융기관보험대리점 수수료율 공시 관련) 사항이다.','판매',array['방카슈랑스수수료공시','금융기관보험대리점수수료','KPUB공시','수수료투명성'],'cycle2_supp','cycle2_supp','손해보험협회 방카모집수수료율공시 안내 (kpub.knia.or.kr) / 보험업감독규정 (law.go.kr)','ai_draft','high','admin'),
('term','보험설계사 등록 말소 (해촉증명서)','보험설계사가 보험회사 또는 GA로부터 위촉 해지(해촉)될 경우 해촉증명서를 발급받아 협회에 등록 말소를 신청해야 한다. 말소 후 재등록 시에는 결격사유가 없는 경우 새로운 소속 회사를 통해 재등록이 가능하다. 손해보험협회 MISI 시스템(misi.knia.or.kr)에서 해촉증명서 말소 신청 기능을 제공한다. 말소 처리가 지연되면 이중 등록 문제가 발생할 수 있다. 내용증명 발송 방식의 해촉 시 발송일로부터 10일 경과 후 말소 신청이 가능하다.','판매',array['보험설계사말소','해촉증명서','등록말소절차','MISI말소신청','이중등록방지'],'cycle2_supp','cycle2_supp','손해보험협회 MISI 해촉증명서 말소 (misi.knia.or.kr) / 보험업법 제84조 (casenote.kr / law.go.kr)','ai_draft','high','admin'),
('term','독립손해사정사 선임권 및 비용 부담','보험계약자·피보험자는 보험회사 손해사정 착수 전에 독립(소비자 선임) 손해사정사를 직접 선임할 수 있으며, 이 경우 비용은 보험회사가 부담한다. 2024년 개선으로 독립손해사정사 선임 여부 판단 기간이 3영업일에서 10영업일로 연장되었다. 선임 가능 대상은 사고조사가 필요한 청구 건으로, 보험사가 손해사정업무 위탁 시 소비자에게 독립손해사정사 선임 관련 사항을 안내하도록 의무화되었다. 근거: 보험업법 제185조, 손해사정 업무위탁 및 손해사정사 선임 등에 관한 모범규준(금감원).','민원',array['독립손해사정사','소비자선임손해사정사','손해사정비용부담','보험금분쟁대응','10영업일'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 / 한국금융신문 ''독립 손해사정사 선임 판단기간 3→10영업일 확대'' (fntimes.com, 2023.11.29) / 보험업법 제185조 (casenote.kr)','ai_draft','medium','admin'),
('term','보험자대위(청구권대위) 구상 실무','보험자가 피보험자에게 보험금을 지급한 후 피보험자가 제3자에 대해 가지는 손해배상청구권을 대위 취득하여 구상하는 제도. 근거: 상법 제682조. 피보험자의 과실이 경합된 경우 보험금 지급 후 피보험자에게 남은 손해를 초과하는 부분만 구상 가능(대법원 2019.11.14. 선고 2019다216589 판결). 인보험(생명·상해보험)에서는 상법 제729조에 의해 원칙적으로 대위 금지. 상해보험은 당사자 약정 시 피보험자 권리를 해하지 않는 범위에서 예외 허용.','계약',array['청구권대위','보험자대위','구상권','상법제682조','상법제729조'],'cycle2_supp','cycle2_supp','상법 제682조·제729조 (law.go.kr) / 대법원 2019.11.14. 선고 2019다216589 판결 (casenote.kr / KCI)','ai_draft','high','admin'),
('term','자살면책 2년 조항 — 정신질환 예외','생명보험 표준약관에서 자살은 우발성 결여로 원칙적 면책이나 두 가지 예외가 있다. 1) 보장개시일로부터 2년 경과 후 자살 시 재해 이외 원인에 의한 사망보험금 지급(자살면책 2년 조항), 2) 정신질환 등으로 자유로운 의사결정 불가 상태의 자해·자살. 2항 판단은 나이·신체정신상황·정신질환 진행경과·주위상황·행위 시기·방법 등 종합 고려(대법원 판례). 재해사망보험금은 자살면책 2년 경과 후에도 ''재해'' 해당 여부 별도 판단이 필요하며, 정신질환으로 인한 자살은 재해사망보험금 지급 대상이 될 수 있다.','보장',array['자살면책','정신질환예외','자살보험금','생명보험표준약관','2년조항'],'cycle2_supp','cycle2_supp','생명보험 표준약관(보험업감독업무시행세칙 별표 15) / 국가법령정보센터 판례(precSeq=181043) / easylaw.go.kr 보험금 지급사유 및 면책사유 예시','ai_draft','high','admin'),
('term','보험금 지급기한(생명·손해보험 비교)','생명보험 및 질병·상해 손해보험: 청구서류 접수일로부터 3영업일 이내 지급, 조사·확인 필요 시 10영업일 이내. 화재·배상책임보험: 손해액 결정 후 7일 이내. 자동차보험: 7일 이내. 조사 장기화 시 30영업일 이내 지급예정일 통지 의무. 근거: 보험업감독업무시행세칙 별표 15 생명보험·손해보험 표준약관 지급일 조항.','민원',array['보험금지급기한','3영업일','7일이내','지급기일','표준약관'],'cycle2_supp','cycle2_supp','찾기쉬운 생활법령 ''보험금 지급개관'' (easylaw.go.kr) / 보험업감독업무시행세칙 별표 15 표준약관','ai_draft','medium','admin'),
('term','보험계약 해지 후 보험금청구권 존부(상법 제655조)','상법 제655조: 보험사고 발생 후 보험자가 계약을 해지해도 원칙적으로 보험금 지급 책임 없음. 단, 고지의무 위반 사실 또는 위험 변경·증가 사실이 보험사고 발생에 영향을 미치지 않았음이 증명된 경우 보험금 지급 책임 있음(동조 단서). 인과관계 부존재의 입증책임은 보험계약자·피보험자 측이 부담(대법원 확립 판례). 고지의무 위반 해지와 보험금 지급의 핵심 조항.','계약',array['상법제655조','해지후보험금','고지의무위반인과관계','보험금청구권존부'],'cycle2_supp','cycle2_supp','상법 제655조 (casenote.kr / law.go.kr) / 대법원 판례 (precSeq=600295 등) / 찾기쉬운 생활법령 보험계약 무효·해지 (easylaw.go.kr)','ai_draft','high','admin'),
('term','보험약관 작성자불이익 원칙','보험약관이 객관적으로 다의적으로 해석되고 각 해석이 합리성을 가질 경우 고객에게 유리하게 해석해야 한다는 원칙(약관의 규제에 관한 법률 제5조 제2항, 대법원 판례). 단, 약관 조항이 일의적으로 명확히 해석되는 경우에는 적용 불가. 보험금 지급 범위·면책 조항 해석 분쟁에서 보험계약자가 활용하는 핵심 논거. 무조건 소비자 유리 해석은 아니며 약관 목적·취지, 평균적 고객 이해가능성 기준이 전제됨.','민원',array['작성자불이익원칙','약관해석','보험약관해석원칙','보험금분쟁'],'cycle2_supp','cycle2_supp','약관의 규제에 관한 법률 제5조 (casenote.kr / law.go.kr) / 대법원 2018.6.28. 선고 2018다203395 판결 (casenote.kr) / 대법원 2018.7.24. 선고 2017다256828 판결','ai_draft','high','admin'),
('term','실손보험 청구 전산화(실손24)','2023년 10월 보험업법 개정(법률 제19780호)으로 2024년 10월 25일부터 실손보험 청구 전산화 시행. 1단계(2024.10): 병원·보건소 대상, 2단계(2025.10.25): 의원·약국까지 확대. 보험가입자가 보험개발원 ''실손24'' 앱·웹(silson24.or.kr)을 통해 진료비 관련 서류를 병원에서 보험사로 전자 전송하여 보험금 청구 가능. 전산시스템 구축·운영 비용은 보험회사 부담. 종이서류 없이 청구 가능 서류: 영수증, 진료비 세부산정내역서, 처방전.','민원',array['실손24','실손보험 청구 전산화','전자청구','보험업법 개정 2024','보험금 간편 청구'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 fsc.go.kr/no010101/85456 / 대한민국 정책브리핑 korea.kr ''실손보험 청구 전산화가 의원·약국으로 확대 시행''','ai_draft','high','admin'),
('term','보험 의료자문 공정성 문제','보험사가 보험금 지급 심사 과정에서 보험사 측 자문의 소견을 이유로 주치의 진단을 번복하거나 보험금을 거절·감액하는 관행. 중립성·공정성 논란이 지속되어 금감원-의협 간 업무협약(MOU)을 통한 제3의료자문 절차가 도입됨. 보험계약자는 보험사 자문의 의견만으로 지급 거부 시 이의 제기 및 분쟁조정 가능. 시범사업은 심·뇌혈관 질환, 후유장애 진단 관련 의료자문으로 대상을 한정하여 6개월 운영 후 확대 여부를 점검하는 방식으로 운영 중.','민원',array['의료자문','자문의','보험금 거부','의협 MOU','분쟁민원'],'cycle2_supp','cycle2_supp','의협신문 doctorsnews.co.kr ''공정성 논란 보험사 셀프 자문 차단'' / 금감원-의협 업무협약 관련 보도 bosa.co.kr 2024','ai_draft','medium','admin'),
('term','사망보험금 간주상속재산 과세(상속세 및 증여세법 제8조)','피상속인이 보험계약자이거나 실질적으로 보험료를 납부한 경우, 그 사망으로 지급받는 생명·손해보험 사망보험금은 상속세 및 증여세법 제8조에 따라 상속재산으로 간주하여 상속세 과세. 보험금 중 상속세 과세 금액: 수령 보험금 × (피상속인 납부 보험료 / 총 납부 보험료 합계). 수익자가 법정상속인인 경우 상속 고유재산이나 계약자가 피상속인이면 간주상속재산으로 과세됨.','세제',array['사망보험금 상속세','간주상속재산','상속세 및 증여세법 제8조','보험금 과세'],'cycle2_supp','cycle2_supp','상속세 및 증여세법 제8조(국가법령정보센터 law.go.kr) / TAXLY ''상속재산으로 보는 보험금(간주상속재산)'' taxly.kr','ai_draft','high','admin'),
('term','보험수익자 사망 후 보험금 귀속(상법 제733조)','지정 보험수익자가 피보험자보다 먼저 사망하고 계약자가 수익자를 재지정하지 않으면, 상법 제733조 제3항·제4항에 따라 사망한 수익자의 상속인이 수익자가 됨. 대법원 2025.2.20. 선고 2022다306048 중요판결: 지정 수익자 사망 후 재지정 없이 보험사고 발생 시, 수익자 상속인이 생존하지 않은 경우 순차 상속인 중 보험사고 발생 당시 생존한 자가 수익자가 됨. 보험수익자가 여럿인 경우 법정상속분 비율로 보험금청구권 취득. 수익자 미지정 시 피보험자(사망자)의 법정상속인이 수익자(상속인의 고유재산으로 상속채무와 분리).','계약',array['보험수익자 사망','수익자 재지정','상법 제733조','보험금 귀속','법정상속인'],'cycle2_supp','cycle2_supp','대법원 2025.2.20. 선고 2022다306048 판결(scourt.go.kr 판례속보 seqnum=10298) / 국가법령정보센터 law.go.kr 판례 precSeq=604041','ai_draft','high','admin'),
('term','보험계약대출(약관대출) 원리금 초과 시 계약 해지','보험계약대출(약관대출) 원리금이 해약환급금을 초과하면 보험사가 보험계약을 자동 해지(상계 처리)할 수 있음. 미납 이자는 별도 연체이자 없이 원금에 가산되며 복리로 불어남. 계약 해지 시 신용정보원에 연체 기록은 남지 않음. 설계사의 해지 위험 안내 의무가 실무적 민원 포인트. 자동대출납입 특약과 혼동 주의.','계약',array['약관대출','보험계약대출','원리금 초과 해지','해약환급금','복리 이자'],'cycle2_supp','cycle2_supp','금감원 소비자 주의보 insjournal.co.kr ''보험 약관대출 미상환 땐 연금 못 받을 수도'' / 뱅크샐러드 ''보험계약대출 이자 한도'' banksalad.com','ai_draft','high','admin'),
('term','휴면보험금 조회 및 청구 — 내보험 찾아줌','소멸시효(3년)가 완성된 보험금은 보험회사가 서민금융진흥원에 출연하기 전까지 ''휴면보험금''으로 보관됨. 금감원 파인(fine.fss.or.kr) 및 생명·손해보험협회 공동 운영 ''내보험찾아줌(cont.insure.or.kr)''에서 365일 24시간 통합 조회·간편 청구 가능. 정부24, 어카운트인포, 카카오뱅크 등 다양한 채널로도 신청 가능. 소멸시효 완성 후에도 채권은 존재하므로 청구 시 지급 가능.','민원',array['휴면보험금','내보험찾아줌','숨은 보험금','금감원 파인','보험금 조회'],'cycle2_supp','cycle2_supp','금감원 파인 fine.fss.or.kr ''내보험 찾아줌'' / 생명·손해보험협회 공동 운영 cont.insure.or.kr / 정부24 gov.kr ''휴면예금과 휴면보험금의 조회 및 지급신청''','ai_draft','high','admin'),
('term','한국표준질병사인분류(KCD) 외인 코드와 재해보험','보험약관의 재해분류표는 한국표준질병사인분류(KCD) V·W·X·Y 코드 범주(외인: 손상·중독·기타)와 연계됨. 재해사망·재해장해 보험금 청구 시 사망진단서 또는 장해진단서의 KCD 코드가 재해분류표 범위 내인지 여부로 지급 여부 결정. 질병 코드(A~N)와 외인 코드(V~Y)의 구분이 보험금 지급 분쟁의 핵심. 질병분류정보센터(koicd.kr)에서 코드 조회 가능.','보장',array['KCD 코드','외인 코드','재해분류표','재해사망 판단','한국표준질병사인분류'],'cycle2_supp','cycle2_supp','질병분류정보센터 KOICD koicd.kr / 찾기쉬운 생활법령 ''보험의 종류에 따른 보험금 지급사유 및 면책사유 예시'' easylaw.go.kr csmSeq=526','ai_draft','high','admin'),
('term','장해보험금 장해판정시기 및 청구 시점','장해보험금은 장해가 ''확정''된 시점에 청구 가능. 일반적으로 사고·진단확정일로부터 180일(6개월) 경과 후 판정하나, 의사 판단으로 영구장해가 명확히 확정된 경우 180일 전에도 청구 가능. 180일 이내에 장해지급률이 확정되지 않으면 180일이 되는 날의 의사 진단에 기초하여 고정될 것으로 인정되는 상태를 기준으로 결정. 청구권 소멸시효는 3년이며, 기왕 사고의 후유장해도 장해 진단일로부터 3년 이내 청구 가능.','보장',array['장해보험금 청구시점','장해판정시기','180일','영구장해','후유장해 소멸시효'],'cycle2_supp','cycle2_supp','하나생명 청구사유별 안내 장해보험금 hanalife.co.kr / 보험연구원(KIRI) ''보험금청구권과 소멸시효'' kiri.or.kr','ai_draft','medium','admin'),
('term','지정대리청구인 임의대리인 구분','지정대리청구인: 치매·중대질병·중대상해 등으로 본인 청구 불가 시를 대비해 계약 시 또는 보험기간 중 사전 지정(배우자 또는 3촌 이내 친족, 동거 또는 생계 동일). 특약 가입 필요. 임의대리인: 수익자의 위임장·인감증명서 첨부로 일시적 대리 청구 가능, 사전 지정 불필요. 지정대리청구인은 보험사가 본인 확인 없이 처리 가능한 반면 임의대리인은 서류 심사 강화. 생명보험 표준약관에 별도 특약으로 규정.','계약',array['지정대리청구인','임의대리인','보험금 대리청구','치매 대리청구','보험금 청구 대리'],'cycle2_supp','cycle2_supp','금융감독원 표준약관(fss.or.kr 금융소비자보호 표준약관 목록) / 보험업감독업무시행세칙 별표15(국가법령정보센터 law.go.kr) / 찾기쉬운 생활법령 보험금 지급(easylaw.go.kr)','ai_draft','medium','admin'),
('term','인보험 대위 금지(상법 제729조) 및 상해보험 예외','상법 제729조: 생명보험 등 인보험에서 보험자는 피보험자·수익자의 제3자에 대한 권리를 대위 행사할 수 없음(인보험 대위 금지 원칙). 이는 피보험자 보호와 이중이득 허용 의도에 근거. 단, 상해보험에서 당사자 간 약정이 있으면 피보험자의 권리를 해하지 않는 범위에서 예외적 대위 가능(동조 단서). 결과적으로 같은 사고에서 제3자 손해배상금과 보험금을 동시 수령 가능(인보험 이중이득 허용).','계약',array['인보험 대위 금지','상법 제729조','상해보험 예외 대위','이중이득 허용'],'cycle2_supp','cycle2_supp','상법 제729조(국가법령정보센터 law.go.kr / LBOX lbox.kr) / 대법원 2014. 10. 15. 선고 2012다88716 판결(casenote.kr) / 찾기쉬운 생활법령 인보험(easylaw.go.kr)','ai_draft','high','admin'),
('term','약관 설명의무 위반과 편입통제(약관 배제 효과)','보험자가 보험약관의 명시·설명의무를 위반하여 계약을 체결한 경우, 그 약관 내용을 보험계약의 내용으로 주장할 수 없다(약관규제법 제3조 제4항). 상법 제638조의3과 약관규제법 제3조는 동일한 설명의무를 부과하고, 위반 효과로 전자는 1개월 이내 취소권, 후자는 약관의 계약 편입 배제를 각각 정한다. 판례는 양법적용설을 취하여 두 효과가 중첩적으로 적용됨을 인정한다(대법원 96다4893 등). 단, 거래상 일반적이고 공통된 사항, 이미 법령에 정하여진 것을 되풀이하는 정도의 사항에는 설명의무가 인정되지 않는다.','계약',array['약관편입통제','설명의무위반','약관배제','상법638조의3','약관규제법제3조','편입통제'],'cycle2_supp','cycle2_supp','약관의 규제에 관한 법률 제3조(casenote.kr) / 상법 제638조의3(casenote.kr) / 대법원 1996. 4. 12. 선고 96다4893 판결(casenote.kr) / 보험약관 설명의무에 대한 연구(보험연구원 연구보고서 2023-19)','ai_draft','medium','admin'),
('term','작성자 불이익 원칙(보험약관 해석)','보험약관 해석은 평균적 고객의 이해가능성을 기준으로 객관적·획일적으로 하여야 하며, 이 방법으로도 약관 조항이 다의적으로 해석되고 각 해석이 합리성이 있는 경우에 한하여 보충적으로 고객에게 유리하게 해석(작성자 불이익 원칙)을 적용한다. 하나의 합리적 해석만 가능하다면 그것이 고객에게 불리하더라도 동 원칙은 적용되지 않는다(보충적 해석원칙). 대법원 2018다203395, 2017다256828 판결이 주요 선례. 법적 근거는 약관규제법 제5조 제2항.','계약',array['작성자불이익원칙','약관해석','다의적해석','보충적해석','평균적고객기준','약관규제법5조'],'cycle2_supp','cycle2_supp','약관의 규제에 관한 법률 제5조(casenote.kr / LBOX lbox.kr) / 대법원 2018. 6. 28. 선고 2018다203395 판결(casenote.kr) / 대법원 2018. 7. 24. 선고 2017다256828 판결(LBOX lbox.kr) / 보험연구원 연구보고서 2022-07','ai_draft','high','admin'),
('term','개별약정 우선 원칙(보험계약)','약관규제법 제4조는 약관에서 정하는 사항에 관하여 사업자와 고객이 약관 내용과 다르게 합의한 경우 그 합의(개별약정)가 약관보다 우선하여 계약 내용이 됨을 규정한다. 보험계약에서도 보험자와 계약자가 표준약관과 다르게 개별 합의한 내용은 약관에 우선 적용된다. 다만 상법 제663조(불이익변경금지 원칙)와의 관계상, 개별약정이라도 보험계약자에게 불리한 방향으로 상법 강행규정을 배제할 수는 없다.','계약',array['개별약정우선','약관규제법4조','개별합의','약관우선순위','불이익변경금지'],'cycle2_supp','cycle2_supp','약관의 규제에 관한 법률 제4조(국가법령정보센터 law.go.kr / casenote.kr) / 보험연구원 연구보고서 2023-19','ai_draft','high','admin'),
('term','불이익변경금지 원칙(상법 제663조)','상법 제663조는 보험편의 규정을 당사자 간 특약으로 보험계약자·피보험자·보험수익자의 불이익으로 변경하지 못한다고 규정하는 상대적 강행규정이다. 다만 재보험 및 해상보험 기타 이와 유사한 보험의 경우에는 이 원칙이 적용되지 않는다(동조 단서). 따라서 약관이 상법 보험편 규정보다 보험계약자에게 불리한 내용을 정하면 당해 약관 조항은 무효가 된다. 보험계약자에게 유리한 방향의 변경(상법보다 넓은 보장 등)은 허용된다.','계약',array['불이익변경금지','상법663조','강행규정','약관무효','보험계약자보호'],'cycle2_supp','cycle2_supp','상법 제663조(국가법령정보센터 law.go.kr / LBOX lbox.kr) / 대법원 1996. 12. 20. 선고 96다23818 판결(casenote.kr)','ai_draft','medium','admin'),
('term','보험계약 부활 시 고지의무 재발생','실효된 보험계약이 부활될 때 부활계약은 신계약에 준하는 성격을 가지므로 보험계약자·피보험자에게 고지의무가 재발생한다. 부활청약 시점의 건강상태·직업 등 중요한 사항을 보험자에게 다시 고지해야 하며, 이를 위반하면 보험자는 상법 제651조에 따라 계약을 해지할 수 있다. 부활 이후 고지의무 위반을 이유로 한 해지권 제척기간(안날로부터 1월, 부활일로부터 3년)도 부활일을 기산점으로 새로 진행된다.','계약',array['부활시고지의무','부활계약고지','실효부활고지','상법650조의2','고지의무재발생'],'cycle2_supp','cycle2_supp','상법 제650조의2 준용규정(casenote.kr / law.go.kr) / 상법 제651조(casenote.kr) / 찾기쉬운 생활법령 보험계약 부활(easylaw.go.kr)','ai_draft','high','admin'),
('term','타인을 위한 보험(상법 제639조) — 계약 구조와 권리 귀속','보험계약자는 위임 유무와 무관하게 특정 또는 불특정의 타인을 위하여 보험계약을 체결할 수 있다(상법 제639조). 손해보험에서는 피보험자, 생명보험에서는 보험수익자가 ''타인''에 해당하며, 타인은 별도 의사표시 없이 당연히 계약의 이익을 받는다. 보험계약자는 원칙적으로 보험금청구권을 갖지 않으며, 보험계약자가 파산하거나 보험료 지급을 지체한 경우 타인도 보험료 납입의무를 부담할 수 있다.','계약',array['타인을위한보험','상법639조','피보험자권리귀속','보험계약자피보험자분리','타인보험이익'],'cycle2_supp','cycle2_supp','상법 제639조(국가법령정보센터 law.go.kr / casenote.kr) / 찾기쉬운 생활법령 타인의 동의 없는 보험(easylaw.go.kr)','ai_draft','high','admin'),
('term','타인의 생명보험과 피보험자 서면동의(상법 제731조)','타인의 사망을 보험사고로 하는 생명보험계약은 계약 체결 시까지 피보험자의 서면 동의를 반드시 받아야 한다(상법 제731조 제1항). 동의는 각 계약별 개별적 서면동의여야 하며 포괄·묵시·추정 동의로는 부족하다. 이 규정은 강행규정으로, 서면동의 없이 체결된 계약은 확정적 무효이며 사후 추인으로도 유효화될 수 없다(대법원 2004다56677). 도박보험 방지·피보험자 살해 위험 방지를 목적으로 한다.','계약',array['타인의생명보험','상법731조','피보험자서면동의','강행규정무효','사망보험동의'],'cycle2_supp','cycle2_supp','상법 제731조(국가법령정보센터 law.go.kr) / 대법원 2006. 9. 22. 선고 2004다56677 판결(casenote.kr / law.go.kr) / 찾기쉬운 생활법령 보험계약 무효(easylaw.go.kr)','ai_draft','high','admin'),
('term','보험수익자 지정·변경권(상법 제733조·제734조)','보험계약자는 보험수익자를 지정·변경할 권리를 가진다(상법 제733조). 이 변경권은 형성권으로서 보험자나 보험수익자의 동의 없이 자유롭게 행사할 수 있으며, 변경의 의사표시가 객관적으로 확인되는 즉시 효력이 발생한다(보험자 도달 불요). 다만 보험자에게 변경 통지를 하지 않으면 보험자에게 대항하지 못한다(상법 제734조). 보험계약자가 변경권을 행사하지 않고 사망하면 보험수익자의 권리가 확정되고, 보험계약자가 지정권을 행사하지 않고 사망하면 피보험자가 보험수익자가 된다.','계약',array['보험수익자변경권','상법733조','상법734조','형성권','수익자지정변경통지'],'cycle2_supp','cycle2_supp','상법 제733조·제734조(국가법령정보센터 law.go.kr / LBOX lbox.kr) / 대법원 2018. 7. 12. 선고 2017다235647 판결(casenote.kr) / 찾기쉬운 생활법령(easylaw.go.kr)','ai_draft','high','admin'),
('term','단체보험(상법 제735조의3) — 규약과 피보험자 동의 예외','단체가 규약에 따라 구성원의 전부 또는 일부를 피보험자로 하는 생명보험계약을 체결하는 경우 피보험자 개별 서면동의(상법 제731조)의 적용이 배제된다(상법 제735조의3 제1항). 단, 규약은 단체협약·취업규칙·정관 등 형식을 불문하고 대표자가 구성원을 위해 일괄 계약을 체결할 수 있다는 취지가 담겨 있어야 한다. 규약 없이 단체보험 형식으로 체결한 계약은 피보험자 개별 서면동의 없이는 무효이다. 보험계약자가 피보험자 외의 자를 수익자로 지정할 때에는 규약에 명시적 정함이 없는 한 피보험자 서면동의 필요.','계약',array['단체보험','상법735조의3','규약동의대체','피보험자동의예외','단체협약취업규칙'],'cycle2_supp','cycle2_supp','상법 제735조의3(국가법령정보센터 law.go.kr); 대법원 2020. 2. 6. 선고 2017다215728 판결(국가법령정보센터 precSeq=210793)','ai_draft','high','admin'),
('term','단체보험 보험금청구권 귀속(대법원 2017다215728)','단체보험계약에서 피보험자의 상속인이 보험수익자로 지정된 경우, 피보험자 사망 시 보험금청구권은 상속인의 고유재산으로 취득하는 것이며 상속재산이 아니다. 따라서 상속인 중 한 명이 보험금청구권을 포기하더라도 포기 부분이 다른 상속인에게 귀속되지 않는다(대법원 2020. 2. 6. 선고 2017다215728). 이는 생명보험 수익자 지정의 법적 성격이 수익자의 고유한 권리임을 확인한 판결이다.','계약',array['단체보험보험금귀속','상속재산제외','고유재산취득','대법원2017다215728','수익자포기'],'cycle2_supp','cycle2_supp','대법원 2020. 2. 6. 선고 2017다215728 판결(국가법령정보센터 precSeq=210793; CaseNote)','ai_draft','high','admin'),
('term','고지의무 해지권 제척기간(상법 제651조) — 1월/3년','보험자의 고지의무 위반으로 인한 계약 해지권은 두 가지 제척기간의 제한을 받는다. 첫째, 위반 사실을 안 날로부터 1개월 이내(상대적 제척기간), 둘째, 계약 체결일로부터 3년 이내(절대적 제척기간). 이 기간이 경과하면 고지의무 위반이 있더라도 해지권이 소멸하여 보험사고 발생 시 보험금을 지급해야 한다. 단, 보험자가 계약 당시 위반 사실을 알았거나 중대한 과실로 몰랐을 경우 해지권이 인정되지 않는다. 2011년 개정 이전에는 절대적 기간이 5년이었으나 현행은 3년이다.','계약',array['고지의무해지권제척기간','상법651조','1개월제척','3년제척','해지권소멸'],'cycle2_supp','cycle2_supp','상법 제651조(국가법령정보센터 law.go.kr); CaseNote 상법 제651조 해설','ai_draft','high','admin'),
('term','고지방해와 고지의무 위반 해지권 제한(보험업법 제97조 제1항 제4호)','보험모집종사자가 보험계약자·피보험자로 하여금 중요 사항을 고지하지 않도록 유도하거나 부실 고지를 방해한 경우, 보험자는 그 고지의무 위반을 이유로 보험계약을 해지할 수 없다(보험업법 제97조 제1항 제4호 위반 + 관련 판례). 설계사의 ''괜찮다''는 유도나 청약서 허위 기재 방조가 이에 해당하며, 이를 주장하려면 보험계약자가 방해 행위를 입증해야 한다. 상법 제651조의2는 ''보험자가 서면으로 질문한 사항은 중요한 사항으로 추정한다''는 규정으로서 고지방해와 직접 관련 없는 별도 조문이다.','계약',array['고지방해','보험업법97조제1항제4호','설계사고지유도','해지권제한','고지의무위반'],'cycle2_supp','cycle2_supp','보험업법 제97조 제1항 제4호(국가법령정보센터 law.go.kr); 상법 제651조의2(국가법령정보센터)','ai_draft','medium','admin'),
('term','고지의무 위반과 보험사고 인과관계(상법 제655조 단서)','보험사고 발생 후 고지의무 위반을 이유로 보험계약을 해지한 경우에도, 고지의무 위반 사실이 보험사고 발생에 영향을 미치지 않았음이 증명되면 보험자는 보험금 지급 책임을 면하지 못한다(상법 제655조 단서). 인과관계 부존재의 입증책임은 보험계약자·피보험자가 부담한다는 것이 대법원 확립 법리(대법원 92다28259 등)이다. 인과관계 없는 보험사고는 해지 후에도 보험금의 전부에 대한 지급 책임이 있다.','계약',array['고지의무위반인과관계','상법655조단서','인과관계없으면보험금지급','해지후보험금','입증책임'],'cycle2_supp','cycle2_supp','상법 제655조(국가법령정보센터 law.go.kr); 대법원 1992. 10. 23. 선고 92다28259 판결(CaseNote); 국가법령정보센터 precSeq=600295(인과관계 판단 사건)','ai_draft','medium','admin'),
('term','보험계약 사고 전 선의 무효(상법 제644조)','보험계약 체결 당시 보험사고가 이미 발생하였거나 발생 가능성이 없는 경우 그 계약은 원칙적으로 무효이다(상법 제644조). 단, 당사자 쌍방과 피보험자 모두가 이를 알지 못한 경우(선의)에는 예외적으로 계약이 유효하다. 관련 당사자 중 한 명이라도 사고 확정 사실을 알았으면 선의 예외가 적용되지 않아 계약은 무효가 된다(대법원 97다50091, 2010다66835).','계약',array['보험사고확정무효','상법644조','선의예외','보험계약무효요건','사고발생불능'],'cycle2_supp','cycle2_supp','상법 제644조(국가법령정보센터 law.go.kr); 대법원 1998. 8. 21. 선고 97다50091 판결(CaseNote); 대법원 2010. 12. 9. 선고 2010다66835 판결(CaseNote)','ai_draft','high','admin'),
('term','보험계약 통지의무(상법 제652조) — 위험변경증가 판단기준','보험기간 중 보험계약자·피보험자가 사고 발생 위험이 현저하게 변경 또는 증가된 사실을 알게 된 경우 지체 없이 보험자에게 통지해야 한다(상법 제652조). 고지의무(계약 체결 시)와 달리 통지의무는 계약 성립 이후 새로운 위험 변화에 대한 의무이다. 하나의 보험회사에 여러 보험계약이 있는 경우 통지의무 이행 여부는 통지의 내용·경위·보험사 처리 경과를 종합하여 판단한다(대법원 2024. 11. 28. 선고 2022다238633).','계약',array['통지의무','상법652조','위험변경증가','고지의무와통지의무구별','대법원2022다238633'],'cycle2_supp','cycle2_supp','상법 제652조(국가법령정보센터 law.go.kr); 대법원 2024. 11. 28. 선고 2022다238633 판결(국가법령정보센터 precSeq=242125)','ai_draft','high','admin'),
('term','보험자 면책 — 고의사고(상법 제659조)','보험사고가 보험계약자·피보험자·보험수익자의 고의로 인하여 발생한 때에는 보험자는 보험금 지급 책임이 없다(상법 제659조 제1항). 다만 사망 또는 상해를 보험사고로 하는 인보험의 경우, 중대한 과실로 인한 사고에 대해서는 보험자가 면책되지 않는다(상법 제659조 제2항). 고의면책은 보험계약자 등의 고의사고를 보장하는 약관 조항은 무효로 하는 강행규정적 성격을 갖는다. 고의 여부 판단은 사고 경위·행위자의 의도 등 전반적 사정을 고려하여 판단한다.','계약',array['고의사고면책','상법659조','보험자면책사유','중대한과실면책제외인보험','면책조항'],'cycle2_supp','cycle2_supp','상법 제659조(국가법령정보센터 law.go.kr); CaseNote 상법 제659조 해설','ai_draft','medium','admin'),
('term','자살면책 2년 조항 — 예외 요건(정신질환·자유의사 결정 불능)','생명보험 약관상 피보험자 자살은 원칙적으로 면책이나, 계약 책임개시일로부터 2년 경과 후 자살은 보험금을 지급하는 예외가 있다. 또한 정신질환 등으로 자유로운 의사결정을 할 수 없는 상태에서 사망한 경우는 자살에 해당하지 않으며 보험금 지급 대상이 된다. 판례는 사망 전 직접 진단·치료 기록이 없더라도 자살자의 나이·성행·정신질환 경과·주위 상황·자살 방법 등 객관적 자료 전반을 종합하여 판단하도록 요구한다(대법원 확립 법리).','계약',array['자살면책2년','자살보험금예외','정신질환자살','자유의사결정불능','자살면책기간'],'cycle2_supp','cycle2_supp','생명보험협회 표준약관(klia.or.kr 자살면책기간 경과 후 보험자 부책 자료); 대법원 2016. 5. 12. 선고 2015다243347 판결(CaseNote); 대법원 2022. 11. 10. 선고 2022다241493 판결(CaseNote)','ai_draft','high','admin'),
('term','보장성보험 해지환급금 압류금지(민사집행법 제246조)','민사집행법 제246조 제1항 제7호는 생명·상해·질병·사고 등을 원인으로 지급받는 보장성보험의 보험금(해약환급금·만기환급금 포함) 채권을 압류금지 채권으로 규정한다. 다만 압류금지 범위는 민사집행법 시행령 제6조에서 구체화하고 있어, 사망보험금 중 1,000만원 이하 등 일정 범위만 절대적 압류금지이며 나머지는 구체적 사정에 따른다. 보장성보험 판단 기준은 만기환급금이 납입보험료 총액을 초과하지 않는 경우가 원칙이나, 보험의 주된 성격·목적도 고려한다(대법원 2007다26165).','계약',array['해지환급금압류금지','민사집행법246조','보장성보험압류불가','강제집행면제','보험금채권압류'],'cycle2_supp','cycle2_supp','민사집행법 제246조(국가법령정보센터 law.go.kr); 민사집행법 시행령 제6조(국가법령정보센터); 대법원 2009. 6. 23. 선고 2007다26165 판결(CaseNote)','ai_draft','medium','admin'),
('term','보험수익자 지정 없을 때 법정수익자 처리(상법 제733조 제2항)','보험계약자가 보험수익자를 지정하지 않은 경우 피보험자가 보험수익자가 된다. 보험계약자가 수익자 지정권을 행사하지 아니하고 사망한 경우에도 피보험자가 보험수익자가 된다(상법 제733조 제2항). 단, 피보험자가 이미 사망한 보험사고 발생 시에는 피보험자의 상속인이 보험금 청구권을 취득한다(대법원 2017다215728 법리). 수익자 변경권을 행사하지 않고 보험계약자가 사망하면 기존 수익자의 권리가 확정된다는 내용은 상법 제733조 제4항에 해당하며, 제2항과는 구분된다.','계약',array['법정수익자','상법733조2항','수익자미지정','피보험자수익자자동결정','수익자권리확정'],'cycle2_supp','cycle2_supp','상법 제733조 제2항(국가법령정보센터 law.go.kr); 대법원 2020. 2. 6. 선고 2017다215728 판결(국가법령정보센터 precSeq=210793)','ai_draft','medium','admin'),
('term','보험계약 승낙 의제(상법 제638조의2) — 30일 미통지 승낙 간주','보험자가 보험계약자로부터 보험료 상당액의 전부 또는 일부를 수령하고 청약을 받은 경우, 다른 약정이 없으면 30일 내에 낙부통지를 발송해야 하며, 이를 게을리하면 보험자가 청약을 승낙한 것으로 본다(상법 제638조의2). 인보험의 피보험자가 신체검사를 받아야 하는 경우에는 신체검사를 받은 날부터 30일을 기산한다. 이 규정은 보험계약 성립을 신속히 확정하고 보험계약자 보호를 목적으로 하며, 부활 청약의 경우에도 준용된다(상법 제650조 제3항).','계약',array['승낙의제','상법638조의2','30일미통지승낙간주','청약승낙','보험계약성립'],'cycle2_supp','cycle2_supp','상법 제638조의2(국가법령정보센터 law.go.kr); 찾기쉬운 생활법령정보 easylaw.go.kr 보험계약의 개관','ai_draft','high','admin'),
('term','보험금청구권 양도·질권 설정 가능성','보험금청구권은 양도 및 질권 설정이 가능하다. 보증보험에서 담보된 채권이 양도되면 당사자 간 별도 약정이 없는 한 보험금청구권도 수반하여 이전된다(대법원 2001. 2. 13. 선고 99다13737). 이 사건에서 대법원은 보증보험이 담보하는 채권이 양도되면 보험금청구권도 채권양수인에게 이전되며, 피보험자 변경 시 보험자 승인을 요구하는 약관은 약관규제법상 무효가 될 수 있다고 판단하였다. 한편 보험사고 발생 전 보험금청구권(정지조건부 권리)의 양도나 질권 설정이 가능한지 여부는 보험 종류 및 약관에 따라 달리 판단될 수 있으며, 보험자에게 대항하려면 보험자에 대한 통지 또는 승낙이 필요하다.','계약',array['보험금청구권양도','보험금질권설정','보증보험채권양도','보험금채권담보','보험자승낙'],'cycle2_supp','cycle2_supp','대법원 2001. 2. 13. 선고 99다13737 판결(국가법령정보센터 precSeq=147598; casenote.kr)','ai_draft','medium','admin'),
('term','보험약관 객관적·획일적 해석 원칙 — 평균적 고객 기준','보험약관은 신의성실 원칙에 따라 공정하고 합리적으로 해석하되, 개개 계약 당사자의 주관적 의도나 목적이 아닌 평균적 고객의 이해가능성을 기준으로 보험단체 전체의 이해관계를 고려하여 객관적·획일적으로 해석해야 한다(대법원 일관된 입장). 위와 같이 객관적·획일적으로 해석한 후에도 약관 조항이 다의적으로 해석되고 각 해석이 합리성을 가져 의미가 명백하지 않은 경우에 한하여 고객에게 유리하게 해석하는 작성자불이익 원칙이 적용된다. 즉 하나의 합리적 해석이 가능하면 그 해석으로 확정되고 작성자불이익 원칙은 적용되지 않는다.','계약',array['약관객관적해석','평균적고객기준','약관획일적해석','보험약관해석원칙','작성자불이익원칙'],'cycle2_supp','cycle2_supp','대법원 2018. 6. 28. 선고 2018다203395 판결(casenote.kr); 보험연구원 보험약관 해석 기준 연구(kiri.or.kr); 성균관법학 대법원 약관해석 법리 비판적 검토(slscc.skku.edu)','ai_draft','high','admin'),
('term','타인의 생명보험 사후 추인 불가 원칙','타인의 생명보험계약에서 피보험자의 서면동의가 계약 체결 시까지 없으면 계약은 확정적으로 무효이며, 계약 체결 이후 피보험자가 추인하더라도 소급하여 유효로 될 수 없다(대법원 2006. 9. 22. 선고 2004다56677). 상법 제731조는 강행규정으로 사후 치유를 허용하지 않으며, 피보험자의 동의는 각 보험계약에 대해 개별적으로 서면으로 이루어져야 하고 포괄적 동의나 묵시적·추정적 동의만으로는 부족하다. 보험자가 수년간 보험료를 수령하거나 보험금을 지급한 사실이 있더라도 무효 주장이 신의성실 원칙에 위반되지 않는다고 대법원은 판단하였다.','계약',array['타인생명보험추인불가','상법731조강행규정','서면동의사후보완불가','계약체결시동의','강행규정소급효'],'cycle2_supp','cycle2_supp','대법원 2006. 9. 22. 선고 2004다56677 판결(국가법령정보센터 precSeq=179446; casenote.kr)','ai_draft','high','admin'),
('term','고지의무의 수동적 응답의무화 논의(질문응답의무)','현행 상법은 보험계약자가 스스로 중요한 사항을 알려야 하는 자발적 고지의무를 규정하나(상법 제651조), 보험자가 서면으로 질문한 사항에 대해서만 응답하는 수동적 응답의무(질문응답의무)로 전환하자는 논의가 있다. 상법 제651조의2는 보험자가 서면으로 질문한 사항을 중요한 사항으로 추정하며 청약서가 이에 해당한다. 프랑스(1989년)·독일(2007년)은 이미 질문응답의무 방식으로 개정하였으며, 국내에서도 개정 논의가 이어지고 있다.','계약',array['질문응답의무','수동적고지의무','상법651조의2','자발적고지의무개정','서면질문사항'],'cycle2_supp','cycle2_supp','상법 제651조의2(국가법령정보센터; casenote.kr); 법률신문 보험계약 전 소비자 자발적 고지의무 수동적 응답의무로','ai_draft','high','admin'),
('term','보험계약 해지환급금 채권자 대위와 강제 해지','채권자가 채무자의 보험계약 해지환급금청구권에 대해 추심명령을 얻으면 보험계약의 해지권을 행사하여 해약환급금을 추심할 수 있다는 것이 대법원의 입장이었다(대법원 2009. 6. 23. 선고 2007다26165). 다만 민사집행법 제246조 및 동법 시행령 제6조는 생명·상해·질병 등에서 발생하는 보장성보험의 해약환급금을 압류금지채권으로 규정하여 채권자에 의한 강제 해지를 제한하고 있다. 보장성보험 여부는 원칙적으로 만기환급금이 납입보험료 총액을 초과하지 않는지를 기준으로 판단하며, 보험의 주된 성격과 목적도 종합 고려한다. 저축성보험(만기환급금이 납입보험료 초과)은 압류가 허용된다.','계약',array['해지환급금채권자대위','추심명령해지','강제해지','보장성저축성구분','압류금지예외'],'cycle2_supp','cycle2_supp','대법원 2009. 6. 23. 선고 2007다26165 판결(casenote.kr); 민사집행법 제246조·시행령 제6조(국가법령정보센터)','ai_draft','medium','admin'),
('term','보험계약 고의 위반 vs 중대한 과실 위반(고지의무 주관적 요건)','고지의무 위반이 성립하려면 보험계약자·피보험자의 고의 또는 중대한 과실이 있어야 한다(상법 제651조). 고의는 중요한 사실을 알면서 고지하지 않거나 허위로 고지하는 것이며, 중대한 과실은 현저한 부주의로 중요한 사항의 존재를 몰랐거나 중요성 판단을 잘못하여 고지하여야 할 중요한 사항임을 알지 못한 것을 의미한다. 단순한 과실이나 착오는 고지의무 위반이 아니다. 고의·중대한 과실의 입증책임은 보험자에게 있다.','계약',array['고지의무주관적요건','고의고지의무위반','중대한과실고지위반','단순과실제외','고지의무입증책임'],'cycle2_supp','cycle2_supp','상법 제651조(국가법령정보센터 law.go.kr); 보험연구원 전문자료 deve34_01.pdf(kiri.or.kr)','ai_draft','high','admin'),
('term','피보험이익 흠결과 손해보험 무효','손해보험계약에서 피보험이익(보험 목적에 대하여 경제적 이해관계)이 없으면 그 계약은 무효이다(상법 제668조). 피보험이익은 적법하고 금전으로 산정 가능한 경제적 이익이어야 하며, 도박·투기 목적의 이익은 피보험이익으로 인정되지 않는다. 피보험이익의 요건은 도박보험 방지 및 이득금지 원칙의 실현을 위해 요구된다. 생명보험은 피보험이익 요건이 손해보험처럼 엄격하게 적용되지 않으나, 타인의 생명보험에서 도박보험 방지를 위해 피보험자의 서면동의 요건이 이를 대체한다.','계약',array['피보험이익흠결무효','손해보험무효','도박보험금지','이득금지원칙','피보험이익적법성'],'cycle2_supp','cycle2_supp','상법 제668조(국가법령정보센터 law.go.kr); 보험법입문/제3장 손해보험(ko.wikibooks.org); 대법원 1998. 9. 18. 선고 96다19765 판결(casenote.kr)','ai_draft','high','admin'),
('term','소액단기전문보험업','보험업법 제2조 및 동법 시행령에 근거하여 도입된 업종으로, 소액·단기 보험만을 전문으로 취급하는 보험회사 유형. 보험기간 1년 이내, 보험금 한도 5천만원, 연간 총수입보험료 500억원 이하 요건이 적용되며, 최저자본금은 20억원으로 일반 보험회사보다 낮게 설정됨. 연금·장기요양 등 장기 보장성 및 고자본 요구 종목(원자력·자동차·화재 등)은 취급 불가. 보험업법 개정(2020. 12. 8.) 이후 보험업법 시행령 개정(2021. 5.)을 통해 세부기준이 마련되어 같은 해 6월부터 시행됨. 제도 도입 초기 신청 실적이 매우 저조하여 운영 부담 완화 필요성이 제기된 바 있다.','계약',array['소액단기전문보험업','미니보험','소액보험','단기보험','최저자본금','보험기간1년','보험금한도','보험업법'],'cycle2_supp','cycle2_supp','금융위원회 보도자료(2021) 보험업법 시행령 개정안 입법예고(소액단기전문보험업 세부기준); 국가법령정보센터 보험업법 시행령; 경향신문 2021.12.26. 소액단기전문보험업 시행 6개월 신청 0건','ai_draft','medium','admin'),
('term','임베디드 보험(Embedded Insurance)','비보험 플랫폼(커머스·모빌리티·여행·금융 등) 이용 과정에서 관련 보험이 자동·선택적으로 내장되어 별도 가입 절차 없이 또는 최소한의 절차로 보험이 제공되는 방식. 보험연구원(KIRI)은 임베디드 보험을 비금융 기업-보험사 간 직접 협력 모델, 핀테크/인슈어테크가 중개자 역할을 하는 모델, 핀테크/인슈어테크가 직접 비금융 기업 역할을 하는 모델 등 세 가지 사업 유형으로 분류한다. 국내에서는 혁신금융서비스(금융규제 샌드박스) 지정을 통해 일부 실험적 운영이 허용되고 있으며, 보험업법상 모집 관련 규제 적용 범위와 보험료 수납 방식이 핵심 규제 쟁점이다.','판매',array['임베디드보험','embedded insurance','내장형보험','플랫폼보험','인슈어테크','혁신금융서비스','샌드박스'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 임베디드 보험 사업모형 사례(eiec.kdi.re.kr); 보험연구원 임베디드보험이란 무엇인가(kiri.or.kr/community)','ai_draft','high','admin'),
('term','온디맨드 보험(On-Demand Insurance)','피보험자가 필요한 시간·활동·장소에 한정하여 즉시 가입·해지할 수 있는 유연한 보험 방식. 특정 활동 시간 동안만 보장이 활성화되며(예: 라이딩 중에만 보장), 디지털·앱 기반으로 운영된다. 국내에서는 퍼마일(운전 시간 기반), 스포츠·레저 분야 하루 보험, 긱워커·플랫폼 종사자 대상 시간제 상해 보험 등으로 출시된 바 있다. 보험연구원(KIRI) 인슈어테크 보고서에서 온디맨드 보험 개념과 국내외 사례가 소개된다. 보험업법상 최단 보험기간 규제 및 모집 규정 적용이 주요 쟁점이다.','계약',array['온디맨드보험','시간제보험','긱워커보험','플랫폼종사자보험','인슈어테크','단기보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 인슈어테크 혁명 현황 점검 및 과제(2017)(kiri.or.kr); 전자신문 인슈어테크 온디맨드보험플랫폼 활성화(etnews.com); 메트로서울 온디맨드보험 상품 출시 기사(metroseoul.co.kr)','ai_draft','medium','admin'),
('term','펫보험(반려동물보험) 보장구조','반려동물의 질병·상해로 인한 동물병원 진료비(수술비·입원비·통원비 등)를 보상하는 손해보험 상품. 금융위원회 ''반려동물보험 제도개선 방안''(2022.10.)에 따르면 자기부담금 구조, 보장 가능 진료 항목 범위, 보험료율 산정을 위한 진료비 통계 부재가 주요 과제로 지적됨. 2024년부터 일반 진료비부터 암·심장수술 등 중증질환(선택형)까지 보장 범위를 선택할 수 있는 상품 구조 개선이 추진되었으며, 핀테크 플랫폼을 통한 펫보험 비교·추천 서비스(2024.7. 잠정 출시)가 이루어짐. 반려동물 등록제·진료항목 표준화(농림부 주관)와 연계해 보험료 적정화를 추진.','보장',array['펫보험','반려동물보험','동물병원진료비','수술비','입원비','자기부담금','보험료비교공시'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 — 반려동물보험 제도개선 방안(2022.10.); 금융위원회 보도자료 — 펫보험 활성화를 위한 정부-업계 협력 강화; 보험연구원 CEO Report 01호(2023.02.)','ai_draft','high','admin'),
('term','운전자보험 형사합의금(교통사고처리지원금)','자동차를 운전 중 교통사고로 타인을 상해 입혀 형사처벌 위험이 발생할 때, 피해자와의 형사합의에 소요되는 비용을 보상하는 운전자보험 특약. ''형사합의금 지원 특약'' 또는 ''교통사고처리지원금 특약''으로 불리며, 교통사고처리특례법상 처벌 특례가 적용되지 않는 중대법규위반(12대 항목) 사고 시 주로 지급 사유가 발생함. 손해배상금과 별도의 형사위로금 성격. 손보사 표준 운전자보험 약관 구조에 포함되며, 금융감독원 표준약관 목록에서 확인 가능.','보장',array['운전자보험','형사합의금','교통사고처리지원금','교통사고처리특례법','중대법규위반','형사위로금','벌금'],'cycle2_supp','cycle2_supp','법제처 찾기쉬운 생활법령정보 — 교통사고 발생시 형사처벌(easylaw.go.kr); 교통사고처리 특례법(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','치아보험 대기기간(면책기간)·감액기간','치아보험에서 보장개시일로부터 일정 기간 동안 보험금을 지급하지 않거나(대기기간·면책기간), 또는 지급 보험금을 일정 비율(통상 50%)로 제한하는 기간(감액기간). 계약 전 이미 발생한 충치 등의 도덕적 해이를 방지하기 위한 제도적 장치. 임플란트·브리지·틀니 등 고가 보철치료는 일반적으로 면책기간·감액기간이 적용되며, 재해(외상)로 인한 치아 손상은 보장개시일을 계약일로 하는 경우도 있음. 상품별·담보별 세부 조건이 상이하므로 약관 확인이 필수.','보장',array['치아보험','대기기간','면책기간','감액기간','임플란트보험','틀니보험','브리지보험','보철치료'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 보험금융연구 제33권 제3호(2022.8.) — 치아보험 손해율 관련; 법제처 찾기쉬운 생활법령정보 — 보험의 종류에 따른 보험금 지급사유 및 면책사유 예시','ai_draft','high','admin'),
('term','치아보험 보장 항목(충치·스케일링·보철)','치아보험에서 보장하는 주요 담보는 충치(우식증) 치료, 잇몸 치료(치주질환), 스케일링, 브리지·틀니·임플란트 등 보철치료, 발치, 신경치료(근관치료)로 구분됨. 비급여 항목 비중이 크고, 임플란트·틀니는 본인일부부담 건강보험 급여화(만 65세 이상)와의 중복 보상 여부가 분쟁 소지. 보철치료 특약은 별도 가입 구조가 일반적이며, 감액기간·면책기간과 함께 손해율 관리 수단으로 활용됨.','보장',array['치아보험','임플란트보험','스케일링보험','충치치료보험','보철치료특약','근관치료','치주치료'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 보험금융연구 제33권 제3호(2022.8.) — 치아보험 손해율 관련; 보험업감독업무시행세칙(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','태아보험(어린이보험 태아가입 특약)','산모가 임신 중(일반적으로 임신 8주 이후~22~24주 이전)에 태아를 피보험자로 하여 가입할 수 있는 어린이보험 또는 태아 전용 보험. 출생 후 발생 가능한 선천성 이상(질환), 출생전후기(주산기·P코드) 질환, 미숙아·저체중아 인큐베이터 비용 등을 보장. 책임개시일은 출생 시점으로 전환되며, 출생 이전 태아 상태에서의 사고는 보장되지 않는 것이 일반적. 법제처 찾기쉬운 생활법령정보(임산부 > 태아 보호하기)에 가입 절차·유의사항이 안내됨.','계약',array['태아보험','태아특약','어린이보험태아가입','선천성이상','주산기질환','저체중아','인큐베이터비용'],'cycle2_supp','cycle2_supp','법제처 찾기쉬운 생활법령정보 — 임산부 > 태아보험 가입(easylaw.go.kr); 보험연구원(KIRI) 연구보고서 — 어린이보험의 성장(2018)','ai_draft','high','admin'),
('term','주산기질환(P코드) 보장','어린이보험·태아보험에서 신생아 시기(출생전후기)에 발생하는 질환을 보장하는 담보. 한국표준질병사인분류(KCD)상 ''P코드(출생전후기에 기원한 특정병태)''에 해당하며, 신생아 뇌출혈(P52), 신생아 황달, 미숙아 합병증 등이 포함됨. 성인 뇌출혈(I코드)과 별도 코드 체계를 가지므로 약관상 명시 여부 확인이 필요. 2013년 하반기 일부 보험사가 신생아 뇌출혈(P52) 보장 구조를 변경하면서 분쟁이 발생한 사례가 있으며, 금융감독원이 진단서 병명 기준 보험금 지급을 권고함.','보장',array['주산기질환','P코드','신생아뇌출혈','출생전후기질환','어린이보험','태아보험','KCD분류'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 연구보고서 — 어린이보험의 성장(2018); 건강보험심사평가원(HIRA) — 한국표준질병사인분류(KCD) 안내','ai_draft','high','admin'),
('term','표적항암약물치료비 특약','암 치료 방법 중 특정 분자 표적에 작용하는 표적항암제(표적치료제)를 사용한 치료 비용을 별도로 보장하는 특약. 일반 세포독성 항암제와 구분하여 별도 담보로 구성되는 경우가 있음. 요양급여 항목과 비급여 항목 모두 보장 여부가 상품별로 다르며, 건강보험 산정특례(암 산정특례)와의 연계가 중요. 보험업감독업무시행세칙 별표(표준약관 참조)에서 항암약물치료의 정의·범위를 확인할 수 있으며, 분쟁 시 KCD 코드와 약물 분류가 쟁점이 됨.','보장',array['표적항암치료비','표적항암특약','항암약물치료비','암보험특약','표적치료제','항암제비용보장'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 연구보고서 — 암보험 약관의 해석과 관련 주요 분쟁 사례(2019); 보험업감독업무시행세칙(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','세포·유전자치료제 보험 보장 이슈','CAR-T세포치료, 줄기세포치료, 유전자치료 등 첨단 바이오의약품에 해당하는 세포·유전자치료제는 고가(수억~수십억원)이면서 건강보험 급여화가 지연되는 경우가 많아, 암보험·실손보험의 비급여 보장 범위 및 보험금 지급 한도가 주요 분쟁·정책 과제로 부상. 첨단재생의료 및 첨단바이오의약품 안전 및 지원에 관한 법률에 따라 세포·유전자치료제의 법적 근거가 마련되어 있으며, 일부 보험사는 별도 첨단치료 특약을 개발·판매 중. ''세포치료제 특약''은 표준화된 약관 명칭이 없어 상품별 조건 확인 필수.','보장',array['세포치료제보험','유전자치료제보험','CAR-T보험','첨단바이오의약품','항암특약','비급여고가치료','암보험'],'cycle2_supp','cycle2_supp','첨단재생의료 및 첨단바이오의약품 안전 및 지원에 관한 법률(국가법령정보센터 law.go.kr); 보험연구원(KIRI) 연구보고서 — 암보험 약관 분쟁사례(2019)','ai_draft','medium','admin'),
('term','유병자 간편심사보험 고지항목 구조','병력이 있는 유병자도 가입 가능하도록 계약 전 알릴 의무(고지항목)를 일반 보험보다 대폭 축소·단순화한 간편심사 보험. 생명보험·장기손해보험 간편심사 상품은 업계 관행상 최근 3개월 입원·수술 여부, 최근 5년 암·뇌·심장질환 진단·치료 여부, 최근 5년 입원·수술 여부 등 3~5문항 내외 구조가 통용됨(이른바 ''3·5·5 구조''). 단, 유병력자 실손의료보험은 별도 기준(2년 이내 입원·수술, 5년 이내 암 진단 등 6항목 구조)으로 운영됨. 고지기간 단축 및 항목 축소로 역선택 위험이 높아 표준 보험 대비 보험료가 상당히 높은 것이 특징. 보험업감독규정 및 시행세칙에 간편심사 상품 요건이 규정됨.','인수',array['유병자보험','간편심사보험','고지항목축소','3문항고지','5년고지기간','유병자가입요건','간편가입'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) Monthly 제4호 — 유병자 전용 보험상품 및 가입 현황(2016.12.); 금융위원회 보도자료 — 유병력자 실손의료보험 출시(fsc.go.kr)','ai_draft','medium','admin'),
('term','간병보험 보험금 지급방식(정액형 vs 실손형)','민영 간병보험의 보험금 지급방식은 크게 정액보상형과 실손보상형으로 구분. 국내 보험회사가 취급하는 장기간병보험은 대부분 정액보상형으로, 간병 필요 상태가 인정되면 약관상 정해진 금액을 일시금 또는 연금 형태로 지급. 공적 노인장기요양보험의 등급판정(1~5등급·인지지원등급) 또는 보험회사 자체 ADL(일상생활수행능력) 기준에 따라 지급 여부 및 금액이 결정됨. 보험연구원(KIRI) 간병보험 관련 유의사항(2025.04.)에 따르면 공적 장기요양등급과 민영 간병보험 지급기준이 반드시 일치하지 않음을 유의해야 함.','보장',array['간병보험','정액형간병보험','실손형간병보험','ADL기준','장기요양등급연계','간병보험지급방식'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 주간동향 — 간병보험 관련 유의사항(2025.04.21.); 보험연구원(KIRI) 주간동향 — 간병보험 약관 개선(2024.12.09.)','ai_draft','high','admin'),
('term','간병보험 ADL(일상생활수행능력) 지급기준','민영 간병보험에서 보험금 지급 여부를 판단하는 핵심 기준. ADL(Activities of Daily Living)은 옷 입기·세면·식사·이동·배뇨·배변 등 일상생활 기본 동작의 수행 가능 여부를 평가함. 보험약관에서 ADL 항목 중 일정 수 이상(예: 6개 중 3개 이상)을 타인의 도움 없이 수행하지 못하는 상태를 ''간병 필요 상태''로 정의하는 것이 일반적. 공적 노인장기요양보험의 장기요양인정점수(52점 이상) 기준과는 별개로 보험사 자체 기준을 사용하는 경우가 있어 민원 발생 소지가 있음.','보장',array['ADL기준','일상생활수행능력','간병보험지급기준','간병필요상태','간병보험','민영장기간병보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 주간동향 — 간병보험 관련 유의사항(2025.04.21.); 보험연구원(KIRI) 주간동향 — 간병보험 약관 개선(2024.12.09.)','ai_draft','high','admin'),
('term','간병보험 약관 명확화(2024~2025 개선)','금융감독원은 2024년 11월 제7차 공정금융 추진위원회를 개최하여 간병인 사용일당 관련 보험약관 개선을 심의하고, 간병보험 약관의 모호한 표현으로 인한 분쟁 우려 해소 및 사회 안전망 강화 필요성을 확인했다. 주요 개선 과제로는 간병 필요 상태의 판정 기준(ADL 항목·판정 주체·재판정 주기), 공적 장기요양등급과 민영 기준 간 차이 안내, 보험금 지급 절차 명확화 등이 포함된다. 소비자는 가입 시 1) 민영 지급기준이 장기요양 등급과 동일한지, 2) 지급기준 충족 판정을 누가(의사·보험회사) 하는지, 3) 보험금 지급 방식(일시금·연금형)을 반드시 확인해야 한다.','민원',array['간병보험약관','간병보험개선','ADL판정주체','간병보험민원','장기요양연계','간병보험지급기준명확화'],'cycle2_supp','cycle2_supp','금융감독원 공정금융추진위원회 제7차 회의 자료(2024.11.) — 간병인 사용일당 보험약관 개선 심의; KDI 경제정보센터(eiec.kdi.re.kr) — 관련 정책자료','ai_draft','high','admin'),
('term','반려동물보험 진료비 표준화 연계','펫보험 활성화의 핵심 과제로, 동물병원별 동일 진료항목에 대한 수가 편차가 크면 합리적 보험료율 산정이 어렵다. 금융위원회·농림축산식품부 합동으로 2022년 10월 반려동물보험 제도개선 방안을 발표하여 다빈도 진료항목 표준화(100개 항목 연내 완료 목표), 진료비 게시 의무화 확대, 반려동물 등록제 개선(생체인식정보 허용, 반려묘 등록 의무화 검토) 등을 추진했다. 2024~2025년 현재 질병 3,511종·진료행위 4,930종의 코드 표준화는 완료됐으나, 진료비 자체의 표준수가제는 미도입 상태로 병원별 가격 차이는 여전히 존재한다. 진료비 표준화 없이는 도덕적 해이·역선택 문제가 지속될 수 있다.','인수',array['펫보험진료비','반려동물보험손해율','동물진료표준화','수의사수가','펫보험역선택','반려동물등록제'],'cycle2_supp','cycle2_supp','금융위원회·농림축산식품부 합동 보도자료 — 반려동물보험 제도개선 방안(2022.10.); 대한민국 정책브리핑(korea.kr) — 관련 후속 보도(2024~2025)','ai_draft','medium','admin'),
('term','금융규제 샌드박스(혁신금융서비스) — 보험 분야','금융혁신지원 특별법에 근거하여 금융위원회가 새로운 기술·서비스에 대해 기존 금융법령 규제를 한시적으로 면제·완화하는 제도. 보험 분야에서는 보험비교·추천 플랫폼, AI 기반 보험 심사, 임베디드 보험, 건강 데이터 연계 보험료 할인 등이 혁신금융서비스로 지정됐다. 2019년 제도 시행 이후 2023년까지 보험 분야 다수 건이 포함된 총 293건이 지정됐고, 이 중 169건이 시장에 출시되어 시범 운영 중이다. 지정 기간 만료 후 본인가 전환 또는 관련 법령 개정 절차를 거쳐야 정식 서비스가 가능하다.','판매',array['혁신금융서비스','금융규제샌드박스','인슈어테크','보험샌드박스','금융혁신지원특별법','보험규제특례'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 — 2023년 금융규제 샌드박스 운영성과(fsc.go.kr); 한국핀테크지원센터 금융규제 샌드박스 현황(sandbox.fintech.or.kr)','ai_draft','high','admin'),
('term','지수형 보험(Index-based Insurance, 파라메트릭 보험)','실제 손해 규모 사정 없이 강수량·기온·지진 강도 등 미리 정해진 객관적 지표(인덱스·파라미터)가 약정 수준을 초과(또는 미달)하면 자동으로 보험금을 지급하는 방식. 농작물재해보험·기후리스크 보험에서 활용 사례가 확대되고 있으며, 보험연구원(KIRI)은 기후변화 자연재해 리스크 관리 맥락에서 국내 정책보험·재보험에의 활용 가능성을 분석한 보고서를 발간했다. 손해사정 절차 생략으로 신속 지급이 가능하나, 실제 손해와 지급액 간 ''기저위험(Basis Risk)'' 발생 가능성이 주요 단점이다. 국내에서는 피보험 이익 존재 및 이득 금지 원칙과의 정합성 문제가 상품화의 선결 과제로 논의되고 있다.','보장',array['지수형보험','파라메트릭보험','인덱스보험','기후보험','농작물재해보험','기저위험','자연재해보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) — 기후변화 자연재해 리스크관리 이슈분석 보고서(kiri.or.kr); 보험연구원 E-Conference 파라메트릭 보험의 상품화 방안','ai_draft','high','admin'),
('term','반려동물 등록제와 펫보험 연계','펫보험 가입 및 운영에서 피보험 반려동물의 동일성 확인(동물 특정)이 핵심 과제다. 금융위원회·농림축산식품부 합동 반려동물보험 제도개선 방안(2022.10.)에 따라 기존 내장형 마이크로칩 외에 생체인식정보(홍채·비문 등) 등록을 허용하고, 의무 등록 대상을 반려견에서 반려묘까지 확대하는 방안이 검토 중이다. 동물보호법(국가법령정보센터)에 근거한 등록 정보가 보험 가입 시 피보험 동물 특정 및 보험금 청구 간소화에 연계되어야 보험 인프라가 완성될 수 있다.','인수',array['반려동물등록제','펫보험인프라','동물특정','마이크로칩','반려묘보험','펫보험가입요건'],'cycle2_supp','cycle2_supp','금융위원회·농림축산식품부 합동 보도자료 — 반려동물보험 제도개선 방안(2022.10.); 동물보호법(국가법령정보센터 law.go.kr)','ai_draft','high','admin'),
('term','보험모집 제판분리(제조-판매 분리)','보험의 제조(상품 개발·인수)는 보험회사가, 판매(모집)는 GA(법인대리점) 등 독립 판매 채널이 담당하는 구조 분리. 국내 보험시장에서 GA채널 판매 비중이 지속 확대되면서 제판분리 구조가 심화되고 있다. 금융위원회는 GA에 대한 내부통제 강화·판매책임 강화 정책을 추진 중이며, ''GA 운영위험 평가제도'' 신설을 포함한 보험업감독규정 개정(2024~2025)에서 GA 관리감독 규정이 강화됐다. 보험연구원(KIRI)은 제판분리 심화에 따른 소비자보호 리스크 분석 및 모집규제 재검토 필요성을 연구 보고서로 발간했다.','판매',array['제판분리','GA판매채널','보험판매채널구조','GA내부통제','보험모집시장','GA규제강화'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 — 보험판매채널 소비자 최우선 정책(fsc.go.kr, 2024~2025); 보험연구원(KIRI) — 보험모집시장 환경변화 연구보고서(nre2025-02); 보험업감독규정(국가법령정보센터)','ai_draft','high','admin'),
('term','어린이보험 성인 보장 연장','어린이보험(태아~만 15세 전후 가입 기준)의 보장기간을 만 30세·80세·100세까지 연장하는 구조. 30세 만기 상품에는 보험기간 만료 시 계약전환제도를 활용해 성인 보험으로 무심사 전환하거나 80세·100세로 연장하는 방식이 활용된다. 아이 시절 진단받은 질환이 있어도 보장 유지가 가능한 것이 최대 장점. 단, 보험기간 연장에 따른 보험료 증가, 100세 만기 시 물가·의료비 상승 대비 보험금 실질가치 감소 리스크, 무(저)해지환급형 구조의 납입기간 중 해지환급금 부재 등을 확인해야 한다. 어린이보험과 성인용 보험의 담보 중복 여부도 점검 필요.','계약',array['어린이보험성인연장','어린이보험보장기간','태아보험성인보장','장기어린이보험','어린이보험담보'],'cycle2_supp','cycle2_supp','금융감독원 파인(fine.fss.or.kr) — 보험 가입 전 주요 체크사항; 업계 공시 및 보험사 공식 상품설명서(삼성생명 등 원수사 공식 페이지)','ai_draft','medium','admin'),
('term','간편심사보험 보험료 구조(표준체 대비 할증)','유병자 간편심사보험은 고지항목 축소·대기기간 적용 등을 통해 언더라이팅 위험을 통제하지만, 역선택 위험이 높은 만큼 동일 보장 대비 표준체 보험보다 보험료가 높다. 공식 출처에서 확인되는 수준은 일반적으로 표준체 대비 약 1.5~2배 수준으로, 간편심사 실비보험의 경우 일반 실비보험 대비 1.5~2배가 통상적으로 언급된다. ''3배''까지 할증된다는 표현은 공식 출처에서 확인되지 않으므로 삭제한다. 금융감독원은 유병자(간편고지) 보험 판매 현황 전수조사를 통해 일부 보험사가 적정 요율보다 낮은 보험료를 적용하는 문제도 지적했다. 보험료가 높은 만큼 가입 전 일반 보험 가입 가능 여부를 먼저 확인하는 것이 금감원 파인(FINE)의 권고 사항이다.','인수',array['간편심사보험보험료','유병자보험보험료','표준체비교','역선택위험','간편가입보험료할증','유병자보험가입유의'],'cycle2_supp','cycle2_supp','금융감독원 파인(fine.fss.or.kr) — 보험 가입 전 주요 체크사항; 금융감독원 보도자료 — 간편고지보험 전수조사 관련(헤럴드경제 보도 근거)','ai_draft','medium','admin');
